                        <h4 className="text-[10px] font-black uppercase tracking-widest truncate group-hover:text-gold transition-colors">{p.name}</h4>
                        <div className="flex items-center gap-3">
                           <p className="text-black font-black italic text-sm md:text-lg">{p.price} MAD</p>
                           {p.old_price && <span className="text-[9px] text-red-300 line-through font-bold opacity-50">{p.old_price}</span>}
                        </div>
                        <div className="flex justify-between items-center mt-3 pt-4 border-t border-zinc-50">
                           <span className="text-[8px] text-zinc-400 uppercase font-black tracking-[0.2em] bg-zinc-50 px-3 py-1.5 rounded-full">{p.category}</span>
                           <button 
                            type="button"
                            onClick={(e) => {
                             e.stopPropagation(); 
                             handleDeleteProduct(p);
                           }} className="w-9 h-9 flex items-center justify-center bg-red-50 text-red-400 hover:bg-red-500 hover:text-white rounded-2xl transition-all shadow-sm">
                             <i className="fa-solid fa-trash-can text-[12px]"></i>
                           </button>
                        </div>
                     </div>
                   </motion.div>
                 ))}
               </div>
             )}
          </div>
        )}
      </main>
    </div>
  );
};

