  { name: 'White', hex: '#FFFFFF', border: true },
  { name: 'Red', hex: '#FF0000' },
  { name: 'Blue', hex: '#0000FF' },
  { name: 'Green', hex: '#008000' },
  { name: 'Navy', hex: '#000080' },
  { name: 'Grey', hex: '#808080' },
  { name: 'Beige', hex: '#F5F5DC' },
  { name: 'Gold', hex: '#FFD700' },
  { name: 'Silver', hex: '#C0C0C0' },
  { name: 'Pink', hex: '#FFC0CB' },
  { name: 'Orange', hex: '#FFA500' },
  { name: 'Yellow', hex: '#FFFF00' },
  { name: 'Purple', hex: '#800080' },
  { name: 'Brown', hex: '#A52A2A' },
];

const CATEGORIES = ['Hoodies', 'Pantalons', 'T-Shirts', 'Sneakers', 'Accessoires', 'Packs'];
const LEAD_STATUSES = ['Pending', 'Completed', 'Cancelled'];

interface ToastState {
  id: string;
  variant: 'success' | 'error' | 'info' | 'warning';
  title: string;
  description: string;
}

interface AdminDashboardProps {
  onLogout: () => void;
  triggerConfirm: (title: string, message: string, onConfirm: () => void, confirmLabel?: string) => void;
  setProcessing: (val: boolean) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout, triggerConfirm, setProcessing }) => {
  const [activeTab, setActiveTab] = useState<'nav' | 'add' | 'manage' | 'leads'>('nav');
  const [products, setProducts] = useState<any[]>([]);
  const [leads, setLeads] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [toasts, setToasts] = useState<ToastState[]>([]);

  const [editingId, setEditingId] = useState<number | null>(null);
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [oldPrice, setOldPrice] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [selectedSizes, setSelectedSizes] = useState<string[]>(['M', 'L']);
  const [selectedColors, setSelectedColors] = useState<string[]>(['Black']);
  const [isInStock, setIsInStock] = useState(true);
  const [imageFiles, setImageFiles] = useState<File[]>([]);
  const [existingUrls, setExistingUrls] = useState<string[]>([]);

  useEffect(() => {
    if (activeTab === 'manage') fetchProducts();
    if (activeTab === 'leads') fetchLeads();
  }, [activeTab]);

  const showToast = (variant: ToastState['variant'], title: string, description: string) => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, variant, title, description }]);
    setTimeout(() => removeToast(id), 5000);
  };

  const removeToast = (id: string) => setToasts(prev => prev.filter(t => t.id !== id));

  async function fetchProducts() {
    setLoading(true);
    const { data, error } = await supabase.from('products').select('*').order('id', { ascending: false });
    if (error) showToast('error', 'Erreur', error.message);
    else setProducts(data || []);
    setLoading(false);
  }

  async function fetchLeads() {
    setLoading(true);
    const { data, error } = await supabase.from('product_leads').select('*').order('created_at', { ascending: false });
    if (error) showToast('error', 'Erreur', error.message);
    else setLeads(data || []);
    setLoading(false);
  }

  async function updateLeadStatus(id: number, status: string) {
    const { error } = await supabase.from('product_leads').update({ status }).eq('id', id);
    if (error) showToast('error', 'Erreur', error.message);
    else {
      showToast('success', 'Lead Mis à Jour', `Statut passé à ${status}`);
      fetchLeads();
    }
  }

  const handleLogoutWithConfirm = () => {
    triggerConfirm(
      "Déconnexion",
      "Êtes-vous sûr de vouloir quitter le terminal SWOOP ?",
      onLogout,
      "Quitter"
    );
  };

  const resetForm = () => {
    setEditingId(null); setName(''); setPrice(''); setOldPrice(''); setCategory(CATEGORIES[0]);
    setSelectedSizes(['M', 'L']); setSelectedColors(['Black']);
    setIsInStock(true); setImageFiles([]); setExistingUrls([]);
  };

  const startEdit = (p: any) => {
    setEditingId(p.id); 
    setName(p.name || ''); 
    setPrice(p.price?.toString() || '');
    setOldPrice(p.old_price?.toString() || ''); 
    setCategory(p.category || CATEGORIES[0]);
    setSelectedSizes(p.sizes || []);
    setSelectedColors(p.colors || []); 
    setIsInStock(p.is_in_stock ?? true);
    setExistingUrls(Array.isArray(p.image_url) ? p.image_url : (p.image_url ? [p.image_url] : []));
    setActiveTab('add');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const toggleSize = (size: string) => {
    setSelectedSizes(prev => prev.includes(size) ? prev.filter(s => s !== size) : [...prev, size]);
  };

  const toggleColorName = (colorName: string) => {
    setSelectedColors(prev => 
      prev.includes(colorName) 
        ? prev.filter(c => c !== colorName) 
        : [...prev, colorName]
    );
  };

  const removeExistingPhoto = (index: number) => {
    triggerConfirm(
      "Supprimer Photo",
      "Voulez-vous retirer cette image de la galerie de ce produit ?",
      () => {
        setExistingUrls(prev => prev.filter((_, i) => i !== index));
        showToast('info', 'Galerie', 'Image retirée. N\'oubliez pas de sauvegarder.');
      },
      "Supprimer"
    );
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) setImageFiles(prev => [...prev, ...Array.from(e.target.files!)]);
  };

  const compressImage = async (file: File): Promise<Blob> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const canvas = document.createElement('canvas');
          let width = img.width;
          let height = img.height;
          const MAX_SIZE = 1600;
          if (width > height) {
            if (width > MAX_SIZE) {
              height *= MAX_SIZE / width;
              width = MAX_SIZE;
            }
          } else {
            if (height > MAX_SIZE) {
              width *= MAX_SIZE / height;
              height = MAX_SIZE;
            }
          }
          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          if (!ctx) return reject(new Error('Canvas context failed'));
          ctx.drawImage(img, 0, 0, width, height);
          canvas.toBlob((blob) => {
              if (blob) resolve(blob);
              else reject(new Error('Compression failed'));
            }, 'image/jpeg', 0.8
          );
        };
      };
      reader.onerror = (e) => reject(e);
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedColors.length === 0) {
      showToast('warning', 'Attention', 'Veuillez sélectionner au moins une couleur.');
      return;
    }
    setProcessing(true);
    try {
      let finalUrls = [...existingUrls];
      for (const file of imageFiles) {
        const compressedBlob = await compressImage(file);
        const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.jpg`;
        const { error: uploadError } = await supabase.storage
          .from('product-images')
          .upload(fileName, compressedBlob, { contentType: 'image/jpeg' });
        if (uploadError) throw uploadError;
        const { data: { publicUrl } } = supabase.storage.from('product-images').getPublicUrl(fileName);
        finalUrls.push(publicUrl);
      }

      const payload = {
        name, 
        price: parseFloat(price), 
        old_price: oldPrice ? parseFloat(oldPrice) : null,
        category,
        sizes: selectedSizes, 
        colors: selectedColors, 
        is_in_stock: isInStock,
        image_url: finalUrls
      };

      const { error } = editingId 
        ? await supabase.from('products').update(payload).eq('id', editingId).select()
        : await supabase.from('products').insert([payload]).select();

      if (error) throw error;
      showToast('success', 'Synchronisé', editingId ? 'Article mis à jour' : 'Nouvel article ajouté');
      setActiveTab('manage');
      resetForm();
    } catch (err: any) {
      showToast('error', 'Erreur', err.message);
    } finally {
      setProcessing(false);
    }
  };

  const handleDeleteProduct = (p: any) => {
    triggerConfirm(
      "Suppression Définitive",
      `Êtes-vous sûr de vouloir supprimer "${p.name}" ? Cela le retirera immédiatement du site.`,
      async () => {
        setProcessing(true);
        const { error } = await supabase.from('products').delete().eq('id', p.id);
        if (error) {
          showToast('error', 'Erreur', error.message);
        } else {
          showToast('success', 'Supprimé', 'Le produit a été retiré du catalogue');
          fetchProducts();
        }
        setProcessing(false);
      },
      "Supprimer"
    );
  };

  return (
    <div className="relative min-h-screen bg-[#F9F9F9] text-black">
      <GlassFilter />

      <div className="fixed top-24 right-6 z-[120] flex flex-col gap-3 w-full max-w-sm pointer-events-none">
        <AnimatePresence mode="popLayout">
          {toasts.map(toast => <AlertToast key={toast.id} {...toast} onClose={() => removeToast(toast.id)} />)}
        </AnimatePresence>
      </div>

      <nav className="hidden md:flex fixed top-0 w-full z-50 bg-white/80 backdrop-blur-xl border-b border-zinc-100 py-6 px-10 justify-between items-center">
        <div className="flex items-center gap-10">
          <h1 className="text-xl font-display font-black uppercase tracking-tighter cursor-pointer" onClick={() => setActiveTab('nav')}>SWOOP <span className="text-gold italic">ADMIN</span></h1>
          <div className="flex gap-8">
             <button onClick={() => setActiveTab('nav')} className={`text-[10px] font-black uppercase tracking-widest ${activeTab === 'nav' ? 'text-black' : 'text-zinc-400'}`}>Tableau de Bord</button>
             <button onClick={() => setActiveTab('leads')} className={`text-[10px] font-black uppercase tracking-widest ${activeTab === 'leads' ? 'text-black' : 'text-zinc-400'}`}>Leads</button>
             <button onClick={() => { resetForm(); setActiveTab('add'); }} className={`text-[10px] font-black uppercase tracking-widest ${activeTab === 'add' ? 'text-black' : 'text-zinc-400'}`}>Ajouter Produit</button>
             <button onClick={() => setActiveTab('manage')} className={`text-[10px] font-black uppercase tracking-widest ${activeTab === 'manage' ? 'text-black' : 'text-zinc-400'}`}>Inventaire</button>
          </div>
        </div>
        <div className="flex gap-4">
          <button onClick={() => window.location.hash = '#'} className="text-[10px] font-black uppercase tracking-widest px-4 py-2 border border-black hover:bg-black hover:text-white transition-all rounded-full">Aperçu Site</button>
          <button onClick={handleLogoutWithConfirm} className="text-[10px] font-black uppercase tracking-widest bg-black text-white px-4 py-2 rounded-full">Déconnexion</button>
        </div>
      </nav>

      {/* Mobile Bottom Navigation */}
      <div className="md:hidden fixed bottom-0 left-0 w-full z-[150] bg-white border-t border-zinc-100 flex justify-around items-center py-6 px-6 shadow-2xl rounded-t-[45px] pb-[calc(1.5rem+env(safe-area-inset-bottom))]">
         <motion.button whileTap={{ scale: 0.8 }} onClick={() => setActiveTab('nav')} className={`flex flex-col items-center gap-1.5 ${activeTab === 'nav' ? 'text-black' : 'text-zinc-300'}`}>
            <i className={`fa-solid fa-house-chimney text-xl ${activeTab === 'nav' ? 'text-gold' : ''}`}></i>
            <span className="text-[7px] font-black uppercase tracking-widest">HQ</span>
         </motion.button>
         <motion.button whileTap={{ scale: 0.8 }} onClick={() => setActiveTab('leads')} className={`flex flex-col items-center gap-1.5 ${activeTab === 'leads' ? 'text-black' : 'text-zinc-300'}`}>
            <i className={`fa-solid fa-bullseye text-xl ${activeTab === 'leads' ? 'text-gold' : ''}`}></i>
