import React, { useState, useEffect, useMemo } from 'react';
import { supabase } from '../lib/supabase';
import { AlertToast } from './ui/AlertToast';
import { AnimatePresence, motion } from "framer-motion";
import { GlassFilter } from './ui/LiquidGlass';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const CATEGORIES = ['Hoodies', 'Pantalons', 'T-Shirts', 'Sneakers', 'Accessoires', 'Packs'];
const LEAD_STATUSES = ['Pending', 'Completed', 'Cancelled'];

interface ToastState {
  id: string;
  variant: 'success' | 'error' | 'info' | 'warning';
  title: string;
  description: string;
}

interface AdminDashboardProps {
  onLogout: () => void;
  triggerConfirm: (title: string, message: string, onConfirm: () => void, confirmLabel?: string) => void;
  setProcessing: (val: boolean) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout, triggerConfirm, setProcessing }) => {
  const [activeTab, setActiveTab] = useState<'nav' | 'add' | 'manage' | 'leads' | 'analytics'>('nav');
  const [products, setProducts] = useState<any[]>([]);
  const [leads, setLeads] = useState<any[]>([]);
  const [analyticsData, setAnalyticsData] = useState<any[]>([]);
  const [allEvents, setAllEvents] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [toasts, setToasts] = useState<ToastState[]>([]);

  // Leads UI state
  const [leadSearch, setLeadSearch] = useState('');

  // Quick View State
  const [quickViewProduct, setQuickViewProduct] = useState<any | null>(null);

  // Form states
  const [editingId, setEditingId] = useState<number | null>(null);
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [oldPrice, setOldPrice] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [selectedSizes, setSelectedSizes] = useState<string[]>(['M', 'L']);
  const [selectedColors, setSelectedColors] = useState<string[]>(['Black']);
  const [isInStock, setIsInStock] = useState(true);
  const [existingUrls, setExistingUrls] = useState<string[]>([]);

  useEffect(() => {
    if (activeTab === 'manage') fetchProducts();
    if (activeTab === 'leads') fetchLeads();
    if (activeTab === 'analytics') fetchAnalytics();
  }, [activeTab]);

  const showToast = (variant: ToastState['variant'], title: string, description: string) => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, variant, title, description }]);
    setTimeout(() => removeToast(id), 5000);
  };

  const removeToast = (id: string) => setToasts(prev => prev.filter(t => t.id !== id));

  async function fetchProducts() {
    setLoading(true);
    const { data, error } = await supabase.from('products').select('*').order('id', { ascending: false });
    if (error) showToast('error', 'Erreur', error.message);
    else setProducts(data || []);
    setLoading(false);
  }

  async function fetchLeads() {
    setLoading(true);
    const { data, error } = await supabase.from('product_leads').select('*').order('created_at', { ascending: false });
    if (error) showToast('error', 'Erreur', error.message);
    else setLeads(data || []);
    setLoading(false);
  }

  async function fetchAnalytics() {
    setLoading(true);
    try {
      const { data: leadsData } = await supabase.from('product_leads').select('*');
      const { data: rawAnalytics } = await supabase.from('site_analytics').select('*');
      const { data: productsData } = await supabase.from('products').select('*');

      setLeads(leadsData || []);
      setAllEvents(rawAnalytics || []);
      setAnalyticsData((rawAnalytics || []).filter((a: any) => a.event_name === 'WhatsApp Click'));
      setProducts(productsData || []);
    } catch (e) {
      showToast('error', 'Erreur Data', 'Impossible de charger les analytics');
    }
    setLoading(false);
  }

  const stats = useMemo(() => {
    const totalPotentialRev = (leads || []).reduce((acc, curr) => acc + (Number(curr.total_price) || 0), 0);
    const whatsappClicksCount = (analyticsData || []).length;
    const leadsCount = (leads || []).length;
    const conversionRate = whatsappClicksCount > 0 ? ((leadsCount / whatsappClicksCount) * 100).toFixed(1) : "0";

    // Top 5 Calculation
    const productStatsMap: Record<string, { name: string, views: number, conversions: number, price: number, image: string }> = {};

    // Group clicks (views)
    allEvents.filter(e => e.event_name === 'WhatsApp Click').forEach(e => {
      if (!productStatsMap[e.product_name]) {
        productStatsMap[e.product_name] = { name: e.product_name, views: 0, conversions: 0, price: 0, image: '' };
      }
      productStatsMap[e.product_name].views++;
    });

    // Group leads (conversions)
    leads.forEach(l => {
      if (!productStatsMap[l.product_name]) {
        productStatsMap[l.product_name] = { name: l.product_name, views: 0, conversions: 0, price: 0, image: '' };
      }
      productStatsMap[l.product_name].conversions++;
    });

    // Match with actual product data for images/price
    products.forEach(p => {
      if (productStatsMap[p.name]) {
        productStatsMap[p.name].price = p.price;
        productStatsMap[p.name].image = Array.isArray(p.image_url) ? p.image_url[0] : p.image_url;
      }
    });

    const top5 = Object.values(productStatsMap)
      .map(p => ({
        ...p,
        rate: p.views > 0 ? ((p.conversions / p.views) * 100).toFixed(1) : "0"
      }))
      .sort((a, b) => b.conversions - a.conversions)
      .slice(0, 5);

    const last7Days = [...Array(7)].map((_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - i);
      const dateStr = d.toISOString().split('T')[0];
      const count = (analyticsData || []).filter(a => a.timestamp?.split('T')[0] === dateStr).length;
      return { date: dateStr, clicks: count };
    }).reverse();

    return { totalPotentialRev, conversionRate, top5, chartData: last7Days };
  }, [leads, analyticsData, allEvents, products]);

  const leadCounters = useMemo(() => {
    return {
      all: leads.length,
      pending: leads.filter(l => l.status === 'Pending').length,
      completed: leads.filter(l => l.status === 'Completed').length,
      cancelled: leads.filter(l => l.status === 'Cancelled').length,
    };
  }, [leads]);

  const filteredLeads = useMemo(() => {
    if (!leadSearch) return leads;
    const search = leadSearch.toLowerCase();
    return leads.filter(l => 
      l.order_id?.toLowerCase().includes(search) || 
      l.product_name?.toLowerCase().includes(search)
    );
  }, [leads, leadSearch]);

  async function updateLeadStatus(id: number, status: string) {
    const { error } = await supabase.from('product_leads').update({ status }).eq('id', id);
    if (error) showToast('error', 'Erreur', error.message);
    else {
      showToast('success', 'Lead Mis à Jour', `Statut passé à ${status}`);
      fetchLeads();
    }
  }

  const getStatusStyle = (status: string) => {
    switch(status) {
      case 'Completed': return 'bg-green-500 text-white';
      case 'Cancelled': return 'bg-red-500 text-white';
      case 'Pending': return 'bg-gold text-black';
      default: return 'bg-zinc-100 text-zinc-400';
    }
  };

  const resetForm = () => {
    setEditingId(null); setName(''); setPrice(''); setOldPrice(''); setCategory(CATEGORIES[0]);
    setSelectedSizes(['M', 'L']); setSelectedColors(['Black']);
    setIsInStock(true); setExistingUrls([]);
  };

  const startEdit = (p: any) => {
    setEditingId(p.id); 
    setName(p.name || ''); 
    setPrice(p.price?.toString() || '');
    setOldPrice(p.old_price?.toString() || ''); 
    setCategory(p.category || CATEGORIES[0]);
    setSelectedSizes(p.sizes || []);
    setSelectedColors(p.colors || []); 
    setIsInStock(p.is_in_stock ?? true);
    setExistingUrls(Array.isArray(p.image_url) ? p.image_url : (p.image_url ? [p.image_url] : []));
    setActiveTab('add');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setProcessing(true);
    try {
      const payload = { 
        name, 
        price: parseFloat(price), 
        old_price: oldPrice ? parseFloat(oldPrice) : null, 
        category, 
        sizes: selectedSizes, 
        colors: selectedColors, 
        is_in_stock: isInStock, 
        image_url: existingUrls 
      };
      const { error } = editingId 
        ? await supabase.from('products').update(payload).eq('id', editingId) 
        : await supabase.from('products').insert([payload]);

      if (error) throw error;
      showToast('success', 'Succès', editingId ? 'Produit mis à jour' : 'Produit ajouté');
      setActiveTab('manage'); 
      resetForm();
    } catch (err: any) { 
      showToast('error', 'Erreur', err.message); 
    } finally { 
      setProcessing(false); 
    }
  };

  return (
    <div className="relative min-h-screen bg-[#F9F9F9] text-black pb-20">
      <GlassFilter />
      <div className="fixed top-24 right-6 z-[120] flex flex-col gap-3 w-full max-w-sm pointer-events-none">
        <AnimatePresence mode="popLayout">
          {toasts.map(toast => <AlertToast key={toast.id} {...toast} onClose={() => removeToast(toast.id)} />)}
        </AnimatePresence>
      </div>

      <nav className="hidden md:flex fixed top-0 w-full z-50 bg-white/80 backdrop-blur-xl border-b border-zinc-100 py-6 px-10 justify-between items-center">
        <div className="flex items-center gap-10">
          <h1 className="text-xl font-display font-black uppercase tracking-tighter cursor-pointer" onClick={() => setActiveTab('nav')}>SWOOP <span className="text-gold italic">ADMIN</span></h1>
          <div className="flex gap-8">
             <button onClick={() => setActiveTab('nav')} className={`text-[10px] font-black uppercase tracking-widest ${activeTab === 'nav' ? 'text-black' : 'text-zinc-400'}`}>Tableau de Bord</button>
             <button onClick={() => setActiveTab('analytics')} className={`text-[10px] font-black uppercase tracking-widest ${activeTab === 'analytics' ? 'text-black' : 'text-zinc-400'}`}>Performance</button>
             <button onClick={() => setActiveTab('leads')} className={`text-[10px] font-black uppercase tracking-widest ${activeTab === 'leads' ? 'text-black' : 'text-zinc-400'}`}>Leads</button>
             <button onClick={() => { resetForm(); setActiveTab('add'); }} className={`text-[10px] font-black uppercase tracking-widest ${activeTab === 'add' ? 'text-black' : 'text-zinc-400'}`}>Ajouter</button>
             <button onClick={() => setActiveTab('manage')} className={`text-[10px] font-black uppercase tracking-widest ${activeTab === 'manage' ? 'text-black' : 'text-zinc-400'}`}>Stock</button>
          </div>
        </div>
        <div className="flex gap-4">
          <button onClick={() => window.location.hash = '#'} className="text-[10px] font-black uppercase tracking-widest px-4 py-2 border border-black hover:bg-black hover:text-white transition-all rounded-full">Aperçu Site</button>
          <button onClick={() => triggerConfirm("Déconnexion", "Quitter le terminal SWOOP ?", onLogout, "Quitter")} className="text-[10px] font-black uppercase tracking-widest bg-black text-white px-4 py-2 rounded-full">Déconnexion</button>
        </div>
      </nav>

      <main className="pt-12 md:pt-40 pb-32 container mx-auto px-6 overflow-x-hidden">
        {activeTab === 'nav' && (
          <div className="flex flex-col items-center justify-center gap-12 min-h-[70vh]">
            <h2 className="text-6xl md:text-9xl font-display font-black uppercase tracking-tighter">SWOOP <span className="text-gold italic">HQ</span></h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 w-full max-w-7xl">
