                <i className="fa-solid fa-chart-simple text-2xl group-hover:text-gold mb-4"></i>
                <h3 className="font-display font-black text-xl uppercase group-hover:text-white">Performance</h3>
              </div>
              <div onClick={() => setActiveTab('leads')} className="bg-white p-10 rounded-[40px] border border-zinc-100 hover:bg-black group transition-all cursor-pointer">
                <i className="fa-solid fa-bullseye text-2xl group-hover:text-gold mb-4"></i>
                <h3 className="font-display font-black text-xl uppercase group-hover:text-white">Leads</h3>
              </div>
              <div onClick={() => {resetForm(); setActiveTab('add');}} className="bg-white p-10 rounded-[40px] border border-zinc-100 hover:bg-black group transition-all cursor-pointer">
                <i className="fa-solid fa-plus text-2xl group-hover:text-gold mb-4"></i>
                <h3 className="font-display font-black text-xl uppercase group-hover:text-white">Nouveau</h3>
              </div>
              <div onClick={() => setActiveTab('manage')} className="bg-white p-10 rounded-[40px] border border-zinc-100 hover:bg-black group transition-all cursor-pointer">
                <i className="fa-solid fa-boxes-stacked text-2xl group-hover:text-gold mb-4"></i>
                <h3 className="font-display font-black text-xl uppercase group-hover:text-white">Stock</h3>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'analytics' && (
          <div className="space-y-12 animate-fade-in-up">
            <div className="flex flex-col md:flex-row md:items-end justify-between border-b border-zinc-100 pb-12 gap-8">
              <div className="space-y-2">
                <h2 className="text-5xl md:text-7xl font-display font-black uppercase tracking-tighter">SWOOP <span className="text-gold italic">DATA</span></h2>
                <p className="text-[10px] font-black uppercase text-zinc-400 tracking-[0.6em]">VUE ANALYTIQUE EN TEMPS RÉEL</p>
              </div>
              <button onClick={fetchAnalytics} className="bg-white hover:bg-black hover:text-white px-8 py-5 text-[10px] font-black uppercase tracking-[0.3em] transition-all rounded-3xl border border-zinc-100 flex items-center gap-4 shadow-sm">
                <i className="fa-solid fa-arrows-rotate"></i> RECHARGER
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="bg-black p-8 md:p-12 rounded-[60px] border border-zinc-800 shadow-3xl">
                  <h3 className="text-white text-2xl font-display font-black uppercase tracking-widest mb-10">Traffic Trends</h3>
                  <div className="h-[300px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                      <AreaChart data={stats.chartData}>
                        <defs>
                          <linearGradient id="colorGold" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#D4AF37" stopOpacity={0.3}/>
                            <stop offset="95%" stopColor="#D4AF37" stopOpacity={0}/>
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" stroke="#1f1f1f" vertical={false} />
                        <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{ fill: '#4b5563', fontSize: 10, fontWeight: 900 }} dy={10} />
                        <YAxis axisLine={false} tickLine={false} tick={{ fill: '#4b5563', fontSize: 10, fontWeight: 900 }} />
                        <Tooltip contentStyle={{ backgroundColor: '#000', border: '1px solid #D4AF37', borderRadius: '15px' }} itemStyle={{ color: '#D4AF37', fontWeight: 900, fontSize: '12px' }} />
                        <Area type="monotone" dataKey="clicks" stroke="#D4AF37" strokeWidth={4} fill="url(#colorGold)" />
                      </AreaChart>
                    </ResponsiveContainer>
