               <div className="bg-white p-8 md:p-12 rounded-[60px] border border-zinc-100 shadow-sm">
                  <div className="flex items-center justify-between mb-10">
                    <h3 className="text-black text-2xl font-display font-black uppercase tracking-widest">Top 5 Drops</h3>
                    <span className="text-[10px] font-black uppercase text-zinc-300 tracking-widest italic">Par Conversions</span>
                  </div>
                  <div className="space-y-4">
                    {stats.top5.map((p, idx) => (
                      <div 
                        key={idx} 
                        onClick={() => setQuickViewProduct(p)}
