import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { motion, HTMLMotionProps } from "framer-motion";
import { cn } from "../../lib/utils";
import {
  CheckCircle2,
  AlertTriangle,
  Info,
  XOctagon,
  X,
} from "lucide-react";

const alertToastVariants = cva(
  "relative w-full max-w-sm overflow-hidden rounded-lg shadow-2xl flex items-start p-4 space-x-4 pointer-events-auto",
  {
    variants: {
      variant: {
        success: "",
        warning: "",
        info: "",
        error: "",
      },
      styleVariant: {
        default: "bg-white border border-zinc-200",
        filled: "",
      },
    },
    compoundVariants: [
      {
        variant: "success",
        styleVariant: "default",
        className: "border-green-100",
      },
      {
        variant: "warning",
        styleVariant: "default",
        className: "border-yellow-100",
      },
      {
        variant: "info",
        styleVariant: "default",
        className: "border-blue-100",
      },
      {
        variant: "error",
        styleVariant: "default",
        className: "border-red-100",
      },
    ],
    defaultVariants: {
      variant: "info",
      styleVariant: "default",
    },
  }
);

const iconMap = {
  success: CheckCircle2,
  warning: AlertTriangle,
  info: Info,
  error: XOctagon,
};

const iconColorClasses: Record<string, string> = {
  success: "text-green-500",
  warning: "text-yellow-500",
  info: "text-blue-500",
  error: "text-red-500",
};

export interface AlertToastProps
  extends Omit<HTMLMotionProps<"div">, "title">,
    VariantProps<typeof alertToastVariants> {
  title: string;
  description: string;
  onClose: () => void;
}

const AlertToast = React.forwardRef<HTMLDivElement, AlertToastProps>(
  (props, ref) => {
    // Extracting variant and styleVariant from props explicitly
    const { className, title, description, onClose, ...rest } = props;

    // Explicitly casting to access VariantProps when destructuring from 'rest' isn't picking them up
    const variant = (props as any).variant || 'info';
    const styleVariant = (props as any).styleVariant || 'default';

    const activeVariant = variant;
    const activeStyleVariant = styleVariant;
    const Icon = iconMap[activeVariant as keyof typeof iconMap] || iconMap.info;

    return (
      <motion.div
        ref={ref}
        role="alert"
        layout
        initial={{ opacity: 0, x: 50, scale: 0.9 }}
        animate={{ opacity: 1, x: 0, scale: 1 }}
        exit={{ opacity: 0, scale: 0.95, transition: { duration: 0.2 } }}
        className={cn(alertToastVariants({ variant: activeVariant, styleVariant: activeStyleVariant }), className)}
        {...rest}
      >
        <div className="flex-shrink-0">
          <Icon className={cn("h-5 w-5", iconColorClasses[activeVariant as string])} aria-hidden="true" />
        </div>
        <div className="flex-1">
          <p className="text-[10px] font-black uppercase tracking-widest leading-none mb-1">{title}</p>
          <p className="text-[10px] text-zinc-500 uppercase tracking-wider leading-relaxed">{description}</p>
        </div>
        <div className="flex-shrink-0">
          <button
            onClick={onClose}
            className="p-1 rounded-full text-zinc-300 hover:text-black hover:bg-zinc-100 transition-all"
          >
            <X className="h-4 w-4" />
          </button>
        </div>
      </motion.div>
    );
  }
);

AlertToast.displayName = "AlertToast";
export { AlertToast };

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import ProductCard from './components/ProductCard';
import ProductDetail from './components/ProductDetail';
import Boutique from './components/Boutique';
import AboutSection from './components/AboutSection';
import Footer from './components/Footer';
import AdminLogin from './components/AdminLogin';
import AdminDashboard from './components/AdminDashboard';
import Cart from './components/Cart';
import { Product } from './types';
import { supabase } from './lib/supabase';
import { AnimatePresence, motion } from "framer-motion";
import { CustomLoader } from './components/ui/LiquidGlass';

interface ConfirmationState {
  isOpen: boolean;
  title: string;
  message: string;
  onConfirm: () => void;
  confirmLabel?: string;
}

const App: React.FC = () => {
  const [view, setView] = useState<'home' | 'boutique' | 'product' | 'admin'>('home');
  const [selectedProduct, setSelectedProduct] = useState<any | null>(null);
  const [session, setSession] = useState<any>(null);
  const [featuredProducts, setFeaturedProducts] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  const [processing, setProcessing] = useState(false);
  const [confirmModal, setConfirmModal] = useState<ConfirmationState>({
    isOpen: false,
    title: '',
    message: '',
    onConfirm: () => {},
  });

  const triggerConfirm = (title: string, message: string, onConfirm: () => void, confirmLabel = "Confirmer") => {
    setConfirmModal({ isOpen: true, title, message, onConfirm, confirmLabel });
  };

  const closeConfirm = () => setConfirmModal(prev => ({ ...prev, isOpen: false }));

  const logEvent = async (eventName: string, productName: string) => {
    try {
      const { error } = await supabase.from('site_analytics').insert([
        { 
          event_name: eventName, 
          product_name: productName,
          timestamp: new Date().toISOString()
        }
      ]);
      if (error) throw error;
    } catch (err) {
      console.error("[Analytics] Error:", err);
    }
  };

  const logLead = async (orderId: string, productName: string, price: number, details: string) => {
    try {
      const { error } = await supabase.from('product_leads').insert([
        { 
          order_id: orderId, 
          product_name: productName,
          total_price: price,
          details: details,
          status: 'Pending'
        }
      ]);
      if (error) throw error;
    } catch (err) {
      console.error("[Lead] Critical Error:", err);
    }
  };

  const [cart, setCart] = useState<any[]>(() => {
    const saved = localStorage.getItem('swoop_cart');
    return saved ? JSON.parse(saved) : [];
  });
  const [isCartOpen, setIsCartOpen] = useState(false);

  const LOGO_URL = "https://raw.githubusercontent.com/yahyabmk01/Aymen-Clothes/main/Image_202601181051-removebg-preview.png";

  useEffect(() => {
    localStorage.setItem('swoop_cart', JSON.stringify(cart));
  }, [cart]);

  // Visitor Tracking Logic
  useEffect(() => {
    const hasVisited = sessionStorage.getItem('swoop_visited');
    if (!hasVisited) {
      logEvent('Page View', 'Home');
      sessionStorage.setItem('swoop_visited', 'true');
    }
  }, []);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    const fetchFeatured = async () => {
      setLoading(true);
      const { data, error } = await supabase
        .from('products')
        .select('*')
        .limit(6)
        .order('id', { ascending: false });

      if (!error && data) {
        setFeaturedProducts(data);
      }
      setLoading(false);
    };

    fetchFeatured();

    const handleHashChange = async () => {
      const hash = window.location.hash;
      if (hash === '#admin') {
        setView('admin');
      } else if (hash.startsWith('#product-')) {
        const id = hash.replace('#product-', '');
        const { data } = await supabase.from('products').select('*').eq('id', id).single();
        if (data) {
          setSelectedProduct(data);
          setView('product');
        }
      } else if (hash === '#boutique') {
        setView('boutique');
        setSelectedProduct(null);
      } else {
        setView('home');
        setSelectedProduct(null);
        fetchFeatured(); 
      }
      window.scrollTo(0, 0);
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();
    return () => {
      window.removeEventListener('hashchange', handleHashChange);
      subscription.unsubscribe();
    };
  }, []);

  const handleAddToCart = (item: any) => {
    setCart(prev => {
      const existing = prev.find(i => i.cartId === item.cartId);
      if (existing) {
        return prev.map(i => i.cartId === item.cartId ? { ...i, quantity: i.quantity + item.quantity } : i);
      }
      return [...prev, item];
    });
    setIsCartOpen(true);
  };

  const handleRemoveFromCart = (cartId: string) => {
    setCart(prev => prev.filter(item => item.cartId !== cartId));
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    window.location.hash = '#';
  };

  const renderContent = () => {
    if (view === 'admin') {
      if (!session) return <AdminLogin onLoginSuccess={() => setView('admin')} />;
      return (
        <AdminDashboard 
          onLogout={handleLogout} 
          triggerConfirm={triggerConfirm}
          setProcessing={setProcessing}
        />
      );
    }

    if (view === 'product' && selectedProduct) {
      return (
        <ProductDetail 
          product={selectedProduct} 
          onAddToCart={handleAddToCart} 
          onBack={() => window.location.hash = '#boutique'} 
          logEvent={logEvent}
          logLead={logLead}
        />
      );
    }

    if (view === 'boutique') return <Boutique />;

    return (
      <>
        <Hero />
        <section className="bg-white-luxury py-16 md:py-32 px-6 flex flex-col items-center border-t border-zinc-200">
            <h2 className="text-4xl md:text-8xl font-display font-black text-black-matte uppercase tracking-tighter mb-4 text-center">
              CURATED <span className="text-outline">DROPS</span>
            </h2>
            <div className="w-20 md:w-32 h-[3px] bg-gold mt-4"></div>
        </section>

        <section id="featured" className="relative border-t border-zinc-200 bg-white-luxury">
          <div className="container mx-auto">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 bg-zinc-50 border-x border-zinc-200">
              {loading ? (
                <div className="col-span-full py-20 text-center uppercase tracking-widest text-[10px] text-zinc-400">Chargement...</div>
              ) : (
                featuredProducts.map((p) => (
                  <ProductCard key={p.id} product={p} />
                ))
              )}

              {!loading && (
                <div className="bg-white p-10 md:p-16 flex flex-col items-center justify-center text-center space-y-8 min-h-[500px] border-b border-zinc-200">
                  <h4 className="text-gold text-[10px] font-black uppercase tracking-[0.6em]">CATALOGUE</h4>
                  <button 
                    onClick={() => window.location.hash = '#boutique'}
                    className="group relative px-10 py-4 border border-black text-black font-black uppercase tracking-[0.4em] text-[10px] overflow-hidden hover:text-white transition-colors duration-500"
                  >
                    <span className="relative z-10">VOIR TOUT</span>
                    <div className="absolute inset-0 bg-black translate-y-full group-hover:translate-y-0 transition-transform duration-500"></div>
                  </button>
                </div>
              )}
            </div>
          </div>
        </section>
        <AboutSection />
      </>
    );
  };

  return (
    <div className="min-h-screen font-sans selection:bg-gold selection:text-white bg-white-luxury text-black">
      {view !== 'admin' && <Navbar cartCount={cart.length} onOpenCart={() => setIsCartOpen(true)} />}
      <main>{renderContent()}</main>
      {view !== 'admin' && <Footer />}
      <AnimatePresence>
        {(confirmModal.isOpen || processing) && (
          <div className="fixed inset-0 z-[999999] flex items-center justify-center p-6">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={!processing ? closeConfirm : undefined} className="absolute inset-0 bg-black/80 backdrop-blur-2xl" />
            <AnimatePresence mode="wait">
              {confirmModal.isOpen && !processing && (
                <motion.div key="confirm" initial={{ opacity: 0, scale: 0.8 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.8 }} className="relative bg-white w-full max-w-[340px] p-10 rounded-[45px] shadow-3xl text-center">
                  <h3 className="text-3xl font-display font-black uppercase tracking-tighter mb-4">{confirmModal.title}</h3>
                  <button onClick={() => { confirmModal.onConfirm(); closeConfirm(); }} className="w-full py-6 bg-black text-white rounded-[25px] text-[10px] font-black uppercase mb-3">{confirmModal.confirmLabel}</button>
                  <button onClick={closeConfirm} className="w-full py-6 bg-zinc-100 text-zinc-400 rounded-[25px] text-[10px] font-black uppercase">Annuler</button>
                </motion.div>
              )}
              {processing && (
                <motion.div key="loading" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="relative flex flex-col items-center gap-10">
                  <CustomLoader /><p className="text-[14px] font-black uppercase tracking-[1em] text-white">SYNCHRONISATION...</p>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        )}
      </AnimatePresence>
      <Cart isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} items={cart} onRemove={handleRemoveFromCart} />
    </div>
  );
};

export default App;

