                      <div className="text-sm font-display font-black italic">{l.total_price} MAD</div>
                      <select value={l.status} onChange={e => supabase.from('product_leads').update({status: e.target.value}).eq('id', l.id).then(() => fetchGlobalData())} className={`px-4 py-2 rounded-full text-[8px] font-black uppercase outline-none border-none cursor-pointer ${l.status === 'Completed' ? 'bg-green-50 text-green-500' : l.status === 'Cancelled' ? 'bg-red-50 text-red-500' : 'bg-gold/5 text-gold'}`}>
