                   </div>
                 ))}
                 {filteredLeads.length === 0 && (
                   <div className="py-20 text-center opacity-30 text-[10px] font-black uppercase tracking-widest">Aucune commande trouvée</div>
                 )}
              </div>
           </div>
        )}

        {activeTab === 'manage' && (
           <div className="animate-fade-in-up">
              <div className="flex justify-between items-end mb-10">
                 <h2 className="text-3xl font-display font-black uppercase tracking-tight">DROPS <span className="text-gold italic">LIVE</span></h2>
                 <span className="text-[9px] font-black text-zinc-400 uppercase tracking-widest">{products.length} ARTICLES</span>
              </div>
              <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-6">
                 {products.map(p => (
                   <div key={p.id} onClick={() => setSelectedProduct(p)} className="bg-white p-4 rounded-[40px] border border-white shadow-sm cursor-pointer group hover:shadow-2xl transition-all">
                      <div className="aspect-[3/4] rounded-[30px] overflow-hidden mb-4 bg-zinc-50 border border-zinc-100 relative">
