               <div className="space-y-6 md:space-y-8">
                  <span className="text-[8px] md:text-[9px] font-black text-zinc-400 uppercase tracking-widest">COULEURS</span>
                  <div className="bg-[#F9F9F9] p-6 md:p-10 rounded-[25px] md:rounded-[40px] grid grid-cols-5 md:grid-cols-10 gap-4 md:gap-6">
                     {OFFICIAL_COLORS.map(c => (
