                              className={`w-10 h-10 md:w-12 md:h-12 rounded-full flex items-center justify-center transition-all border-2 ${selectedColors.includes(c.name) ? 'ring-2 ring-black ring-offset-4 scale-110' : 'border-white shadow-sm'}`}
                              style={{ backgroundColor: c.hex }}
                           >
                              {selectedColors.includes(c.name) && <i className={`fa-solid fa-check text-[10px] ${c.name === 'WHITE' ? 'text-black' : 'text-white'}`}></i>}
