               <div className="flex flex-wrap gap-4 md:gap-6">
                  <button 
                    type="button" 
                    onClick={() => fileInputRef.current?.click()}
                    className="w-24 h-32 md:w-32 md:h-44 border-2 border-dashed border-zinc-100 rounded-[25px] md:rounded-[40px] flex flex-col items-center justify-center gap-2 md:gap-4 group hover:bg-zinc-50 transition-all shadow-inner"
                  >
