                 <div className="flex gap-3">
                    <button onClick={() => startEdit(selectedProduct)} className="flex-1 py-5 bg-black text-white rounded-[25px] text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-gold hover:text-black transition-all active:scale-95 min-h-[50px]">MODIFIER</button>
                    <button onClick={() => handleDeleteProduct(selectedProduct)} className="w-16 md:w-20 py-5 bg-red-50 text-red-500 rounded-[25px] hover:bg-red-500 hover:text-white transition-all flex items-center justify-center active:scale-95 min-h-[50px]"><i className="fa-solid fa-trash-can text-base md:text-lg"></i></button>
                 </div>
              </motion.div>
           </div>
        )}
      </AnimatePresence>
    </div>
  );
};

