  triggerConfirm: (title: string, message: string, onConfirm: () => void, confirmLabel?: string) => void;
  setProcessing: (val: boolean) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout, triggerConfirm, setProcessing }) => {
  const [activeTab, setActiveTab] = useState<'nav' | 'add' | 'manage' | 'leads' | 'analytics'>('nav');
  const [products, setProducts] = useState<any[]>([]);
  const [leads, setLeads] = useState<any[]>([]);
  const [allEvents, setAllEvents] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [toasts, setToasts] = useState<any[]>([]);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  const [dateFilterDays, setDateFilterDays] = useState(7);

  const [leadSearch, setLeadSearch] = useState('');
  const [inventorySearch, setInventorySearch] = useState('');
  const [inventoryCategory, setInventoryCategory] = useState('TOUT');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Pending' | 'Completed' | 'Cancelled'>('All');

  const [selectedProduct, setSelectedProduct] = useState<any | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [oldPrice, setOldPrice] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [selectedSizes, setSelectedSizes] = useState<string[]>([]);
  const [selectedColors, setSelectedColors] = useState<string[]>([]);
  const [imageUrls, setImageUrls] = useState<string[]>([]);
  const [isInStock, setIsInStock] = useState(true);

  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      e.preventDefault();
      e.returnValue = 'Voulez-vous vraiment quitter ? Les modifications non enregistrées seront perdues.';
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, []);

  useEffect(() => {
    fetchGlobalData();
  }, [activeTab, dateFilterDays]);

  const showToast = (variant: any, title: string, description: string) => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, variant, title, description }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 5000);
  };

  async function fetchGlobalData() {
    setLoading(true);
    const filterDate = new Date();
    filterDate.setDate(filterDate.getDate() - dateFilterDays);
    const dateStr = filterDate.toISOString();

    try {
      const [pRes, lRes, aRes] = await Promise.all([
        supabase.from('products').select('*').order('id', { ascending: false }),
        supabase.from('product_leads').select('*').gte('created_at', dateStr).order('created_at', { ascending: false }),
        supabase.from('site_analytics').select('*').gte('timestamp', dateStr)
      ]);
      if (pRes.data) setProducts(pRes.data);
      if (lRes.data) setLeads(lRes.data);
      if (aRes.data) setAllEvents(aRes.data);
    } catch (e) { showToast('error', 'Erreur', 'Synchronisation impossible.'); } finally { setLoading(false); }
  }

  const stats = useMemo(() => {
    const realRevenue = leads
      .filter(l => l.status === 'Completed')
      .reduce((acc, curr) => acc + (Number(curr.total_price) || 0), 0);

    const potentialRevenue = leads
      .filter(l => l.status !== 'Cancelled')
      .reduce((acc, curr) => acc + (Number(curr.total_price) || 0), 0);

    const views = allEvents.filter(e => e.event_name === 'Page View').length;
    const clicks = allEvents.filter(e => e.event_name === 'WhatsApp Click').length;
    const cartAdds = allEvents.filter(e => e.event_name === 'Add to Cart').length;

    const conversionRate = views > 0 ? ((clicks / views) * 100).toFixed(1) : "0";

    const chartMap: Record<string, { name: string, views: number, clicks: number }> = {};
    const now = new Date();

    for (let i = dateFilterDays - 1; i >= 0; i--) {
      const d = new Date(now.getTime() - (i * 24 * 60 * 60 * 1000));
      const dateKey = d.toISOString().split('T')[0];
      chartMap[dateKey] = { name: dateKey.slice(5), views: 0, clicks: 0 };
    }

    allEvents.forEach(e => {
      const dateKey = e.timestamp?.split('T')[0];
      if (chartMap[dateKey]) {
        if (e.event_name === 'Page View') chartMap[dateKey].views++;
        if (e.event_name === 'WhatsApp Click') chartMap[dateKey].clicks++;
      }
    });

    const productsMap: Record<string, any> = {};
    // Top 10 LOGIC: Parse multi-product strings ONLY from 'Completed' leads
    leads.filter(l => l.status === 'Completed').forEach(l => {
      const itemStrings = l.product_name.split(', ');
      itemStrings.forEach((itemStr: string) => {
        const baseName = itemStr.split(' [')[0].trim();
        if (!productsMap[baseName]) {
          const p = products.find(prod => prod.name === baseName);
          productsMap[baseName] = { 
            name: baseName, 
            count: 0, 
            img: p?.image_url?.[0] || "https://placehold.co/100x150?text=S"
          };
        }
        productsMap[baseName].count++;
      });
    });

    const top10 = Object.values(productsMap).sort((a, b) => b.count - a.count).slice(0, 10);

    return { 
      realRevenue, 
      potentialRevenue, 
      views, 
      conversionRate, 
      clicks, 
      cartAdds, 
      chartData: Object.values(chartMap), 
      top10 
    };
  }, [leads, allEvents, products, dateFilterDays]);

  const compressImage = async (file: File): Promise<Blob> => {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.src = URL.createObjectURL(file);
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;
        const maxSize = 1200;
        if (width > height) {
          if (width > maxSize) {
            height *= maxSize / width;
            width = maxSize;
          }
        } else {
          if (height > maxSize) {
            width *= maxSize / height;
            height = maxSize;
          }
        }
        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        if (!ctx) return reject(new Error('Canvas context failed'));
        ctx.drawImage(img, 0, 0, width, height);
        canvas.toBlob((blob) => {
          if (blob) resolve(blob);
          else reject(new Error('Blob conversion failed'));
        }, 'image/webp', 0.8);
      };
      img.onerror = reject;
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setProcessing(true);
    const newUrls = [...imageUrls];
    for (const file of Array.from(files) as File[]) {
      try {
        const compressedBlob = await compressImage(file);
        const fileName = `${Date.now()}-${file.name.split('.')[0]}.webp`;
        const { error: uploadError } = await supabase.storage.from('product-images').upload(fileName, compressedBlob, {
            contentType: 'image/webp'
        });
        if (uploadError) { showToast('error', 'Upload Error', uploadError.message); continue; }
        const { data: { publicUrl } } = supabase.storage.from('product-images').getPublicUrl(fileName);
        newUrls.push(publicUrl);
      } catch (err) {
        showToast('error', 'Compression Error', 'Une erreur est survenue lors de l\'optimisation.');
      }
    }
    setImageUrls(newUrls);
    setProcessing(false);
  };

  const deleteFileFromStorage = async (url: string) => {
    try {
      const fileName = url.split('/').pop();
      if (fileName) {
        await supabase.storage.from('product-images').remove([fileName]);
      }
    } catch (err) { console.error("Storage cleanup failed:", err); }
  };

  const handleProductSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setProcessing(true);
    try {
      const payload = { 
        name, 
        price: parseFloat(price), 
        old_price: oldPrice ? parseFloat(oldPrice) : null,
        category, 
        sizes: selectedSizes, 
        colors: selectedColors, 
        image_url: imageUrls,
        is_in_stock: isInStock 
      };
      const { error } = editingId 
        ? await supabase.from('products').update(payload).eq('id', editingId) 
        : await supabase.from('products').insert([payload]);
      if (error) throw error;
      showToast('success', 'Succès', 'Base de données mise à jour.');
      setActiveTab('manage');
      resetForm();
    } catch (err: any) { showToast('error', 'Erreur', err.message); } finally { setProcessing(false); }
  };

  const handleDeleteProduct = async (product: any) => {
    triggerConfirm(
      'Supprimer', 
      'Êtes-vous sûr ? Cette action est définitive et supprimera également les images du serveur.', 
      async () => {
        setProcessing(true);
        if (Array.isArray(product.image_url)) {
          for (const url of product.image_url) {
            await deleteFileFromStorage(url);
          }
        }
        const { error } = await supabase.from('products').delete().eq('id', product.id);
        if (error) {
          showToast('error', 'Erreur', 'Suppression impossible.');
        } else {
          showToast('success', 'Supprimé', 'Le produit a été retiré.');
          setSelectedProduct(null);
          fetchGlobalData();
        }
        setProcessing(false);
      },
      'Supprimer'
    );
  };

  const handleLogoutWithGuard = () => {
    triggerConfirm(
      'Quitter',
      'Vous allez être redirigé vers la page d’accueil. Continuer ?',
      () => onLogout(),
      'Oui, quitter'
    );
  };

  const handleDeleteLead = async (id: number) => {
    triggerConfirm(
      'Supprimer', 
      'Êtes-vous sûr ? Cette action est définitive.', 
      async () => {
        setProcessing(true);
        const { error } = await supabase.from('product_leads').delete().eq('id', id);
        if (error) showToast('error', 'Erreur', 'Action impossible.');
        else { showToast('success', 'Supprimé', 'Commande retirée.'); fetchGlobalData(); }
        setProcessing(false);
      },
      'Supprimer'
    );
  };

  const resetForm = () => {
    setEditingId(null); setName(''); setPrice(''); setOldPrice(''); setCategory(CATEGORIES[0]);
    setSelectedSizes([]); setSelectedColors([]); setImageUrls([]); setIsInStock(true);
    setActiveTab('manage');
  };

  const startEdit = (p: any) => {
    setEditingId(p.id);
    setName(p.name);
    setPrice(p.price.toString());
    setOldPrice(p.old_price?.toString() || '');
    setCategory(p.category || CATEGORIES[0]);
    setSelectedSizes(p.sizes || []);
    setSelectedColors(p.colors || []);
    setImageUrls(Array.isArray(p.image_url) ? p.image_url : [p.image_url]);
    setIsInStock(p.is_in_stock ?? true);
    setActiveTab('add');
    setSelectedProduct(null);
  };

  const filteredLeads = useMemo(() => {
    let result = [...leads];
    if (statusFilter !== 'All') result = result.filter(l => l.status === statusFilter);
    if (leadSearch) {
      const search = leadSearch.toLowerCase();
      result = result.filter(l => l.order_id.toLowerCase().includes(search) || l.product_name.toLowerCase().includes(search));
    }
    return result;
  }, [leads, leadSearch, statusFilter]);

  const filteredInventory = useMemo(() => {
    let result = [...products];
    if (inventoryCategory !== 'TOUT') {
       result = result.filter(p => p.category?.toUpperCase() === inventoryCategory);
    }
    if (inventorySearch) {
       const search = inventorySearch.toLowerCase();
       result = result.filter(p => p.name?.toLowerCase().includes(search));
    }
    return result;
  }, [products, inventoryCategory, inventorySearch]);

  const NavItems = () => (
    <>
      {[
        { id: 'nav', label: 'BUREAU', icon: 'fa-house' },
        { id: 'analytics', label: 'PERFORMANCE', icon: 'fa-chart-line' },
        { id: 'leads', label: 'COMMANDES', icon: 'fa-bullseye' },
        { id: 'manage', label: 'INVENTAIRE', icon: 'fa-boxes-stacked' },
        { id: 'add', label: 'AJOUTER DROP', icon: 'fa-plus' }
      ].map((item) => (
        <button 
          key={item.id} 
          onClick={() => { setActiveTab(item.id as any); setMobileMenuOpen(false); }} 
          className={`flex items-center gap-3 text-[10px] font-black uppercase tracking-widest transition-all p-4 rounded-2xl ${activeTab === item.id ? 'bg-black text-white' : 'text-zinc-400 hover:text-black hover:bg-zinc-100'}`}
        >
          <i className={`fa-solid ${item.icon}`}></i>
          {item.label}
        </button>
      ))}
    </>
  );

  return (
    <div className="relative min-h-screen bg-[#F7F8FA] text-[#1D1D1F] pb-20 overflow-x-hidden">
      <GlassFilter />
      <div className="fixed top-6 right-6 z-[99999] flex flex-col gap-3 w-full max-w-sm pointer-events-none">
        <AnimatePresence mode="popLayout">
          {toasts.map(toast => <AlertToast key={toast.id} {...toast} onClose={() => {}} />)}
        </AnimatePresence>
      </div>

      <nav className="fixed top-0 w-full z-[100] bg-white/70 backdrop-blur-2xl border-b border-white/40 py-4 px-6 md:px-12 flex justify-between items-center h-20 md:h-24">
        <div className="flex items-center gap-6">
          <button onClick={() => setMobileMenuOpen(true)} className="md:hidden text-xl p-2 min-h-[44px] min-w-[44px] flex items-center justify-center"><i className="fa-solid fa-bars-staggered"></i></button>
          <h1 className="text-xl font-display font-black uppercase tracking-tighter">SWOOP <span className="text-gold italic">HQ</span></h1>
          <div className="hidden md:flex gap-2">
            <NavItems />
          </div>
        </div>
        <button onClick={handleLogoutWithGuard} className="text-[10px] font-black uppercase tracking-widest text-red-500 bg-red-50 px-5 py-3 rounded-full hover:bg-red-500 hover:text-white transition-all min-h-[44px]">Quitter</button>
      </nav>

      <AnimatePresence>
        {mobileMenuOpen && (
          <motion.div 
            initial={{ x: '-100%' }} animate={{ x: 0 }} exit={{ x: '-100%' }} 
            className="fixed inset-0 z-[1500] bg-white p-10 flex flex-col gap-4 md:hidden"
          >
            <button onClick={() => setMobileMenuOpen(false)} className="self-end text-xl mb-10 p-2 min-h-[44px]"><i className="fa-solid fa-xmark"></i></button>
            <NavItems />
          </motion.div>
        )}
      </AnimatePresence>

      <main className="pt-24 md:pt-36 container mx-auto px-4 max-w-6xl">
        {activeTab === 'analytics' && (
           <div className="space-y-6 md:space-y-12 animate-fade-in-up pb-20">
             <div className="flex flex-col md:flex-row justify-between items-center gap-4">
                <h2 className="text-2xl md:text-3xl font-display font-black uppercase tracking-tight">VUE D'ENSEMBLE</h2>
                <select 
                  value={dateFilterDays} 
                  onChange={(e) => setDateFilterDays(Number(e.target.value))}
                  className="bg-white px-5 py-4 md:px-6 md:py-4 rounded-2xl md:rounded-3xl border border-zinc-100 text-[9px] md:text-[10px] font-black uppercase tracking-widest outline-none focus:border-gold shadow-sm appearance-none cursor-pointer min-h-[44px]"
                >
                  {DATE_FILTERS.map(f => <option key={f.value} value={f.value}>{f.label}</option>)}
                </select>
             </div>

             <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-3 md:gap-4">
                <div className="bg-[#E7F9EE] p-5 md:p-6 rounded-[25px] md:rounded-[35px] border border-[#BFF0D4] shadow-sm">
                  <span className="text-[6px] md:text-[8px] font-black uppercase tracking-[0.4em] text-green-600/50 block mb-1">C.A RÉEL</span>
                  <p className="text-lg md:text-3xl font-display font-black italic text-green-600 truncate">{stats.realRevenue.toLocaleString()} <span className="text-[8px] md:text-[10px]">MAD</span></p>
                </div>
                <div className="bg-black p-5 md:p-6 rounded-[25px] md:rounded-[35px] shadow-2xl text-white">
                  <span className="text-[6px] md:text-[8px] font-black uppercase tracking-[0.4em] text-zinc-500 block mb-1">C.A POTENTIEL</span>
                  <p className="text-lg md:text-3xl font-display font-black italic truncate">{stats.potentialRevenue.toLocaleString()} <span className="text-gold text-[8px] md:text-[10px]">MAD</span></p>
                </div>
                <div className="bg-white p-5 md:p-6 rounded-[25px] md:rounded-[35px] border border-white shadow-sm">
                  <span className="text-[6px] md:text-[8px] font-black uppercase tracking-[0.4em] text-zinc-400 block mb-1">VISITEURS TOTAUX</span>
                  <p className="text-lg md:text-3xl font-display font-black italic">{stats.views}</p>
                </div>
                <div className="bg-white p-5 md:p-6 rounded-[25px] md:rounded-[35px] border border-white shadow-sm">
                  <span className="text-[6px] md:text-[8px] font-black uppercase tracking-[0.4em] text-zinc-400 block mb-1">AJOUTS PANIER</span>
                  <p className="text-lg md:text-3xl font-display font-black italic">{stats.cartAdds}</p>
                </div>
                <div className="bg-white p-5 md:p-6 rounded-[25px] md:rounded-[35px] border border-white shadow-sm col-span-2 md:col-span-1">
                  <span className="text-[6px] md:text-[8px] font-black uppercase tracking-[0.4em] text-zinc-400 block mb-1">TAUX CLIC WA</span>
                  <p className="text-lg md:text-3xl font-display font-black italic text-gold">{stats.conversionRate}%</p>
                </div>
             </div>

             <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 md:gap-8">
                <div className="bg-white p-4 md:p-10 rounded-[25px] md:rounded-[50px] shadow-sm border border-white">
                   <div className="flex justify-between items-center mb-4 md:mb-10">
                      <h3 className="text-[8px] md:text-[10px] font-black uppercase tracking-widest text-zinc-400">PAGE VIEWS</h3>
                      <i className="fa-solid fa-users-viewfinder text-zinc-100 text-lg md:text-2xl"></i>
                   </div>
                   <div className="h-[180px] md:h-[300px] w-full">
                     <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={stats.chartData}>
                           <defs>
                              <linearGradient id="colorViews" x1="0" y1="0" x2="0" y2="1">
                                 <stop offset="5%" stopColor="#A2A2A2" stopOpacity={0.1}/>
                                 <stop offset="95%" stopColor="#A2A2A2" stopOpacity={0}/>
                              </linearGradient>
                           </defs>
                           <XAxis dataKey="name" fontSize={6} axisLine={false} tickLine={false} />
                           <YAxis fontSize={6} axisLine={false} tickLine={false} />
                           <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', fontSize: '8px' }} />
                           <Area type="monotone" dataKey="views" stroke="#A2A2A2" strokeWidth={2} fill="url(#colorViews)" />
                        </AreaChart>
                     </ResponsiveContainer>
                   </div>
                </div>

                <div className="bg-[#0A0A0A] p-4 md:p-10 rounded-[25px] md:rounded-[50px] shadow-2xl border border-white/5">
                   <div className="flex justify-between items-center mb-4 md:mb-10">
                      <h3 className="text-[8px] md:text-[10px] font-black uppercase tracking-widest text-gold">WA CLICKS</h3>
                      <i className="fa-brands fa-whatsapp text-gold text-lg md:text-2xl opacity-50"></i>
                   </div>
                   <div className="h-[180px] md:h-[300px] w-full">
                     <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={stats.chartData}>
                           <defs>
                              <linearGradient id="colorClicks" x1="0" y1="0" x2="0" y2="1">
                                 <stop offset="5%" stopColor="#D4AF37" stopOpacity={0.3}/>
                                 <stop offset="95%" stopColor="#D4AF37" stopOpacity={0}/>
                              </linearGradient>
                           </defs>
                           <XAxis dataKey="name" stroke="#FFFFFF" fontSize={6} axisLine={false} tickLine={false} tick={{ fill: 'white' }} />
                           <YAxis stroke="#FFFFFF" fontSize={6} axisLine={false} tickLine={false} tick={{ fill: 'white' }} />
                           <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="rgba(255,255,255,0.05)" />
                           <Tooltip contentStyle={{ backgroundColor: '#111', border: 'none', borderRadius: '12px', color: '#fff', fontSize: '8px' }} />
                           <Area type="monotone" dataKey="clicks" stroke="#D4AF37" strokeWidth={2} fill="url(#colorClicks)" />
                        </AreaChart>
                     </ResponsiveContainer>
                   </div>
                </div>
             </div>

             <div className="bg-white p-6 md:p-12 rounded-[25px] md:rounded-[55px] shadow-sm border border-white">
                <h3 className="text-lg md:text-xl font-display font-black uppercase mb-8 md:mb-10 tracking-widest">Top 10 des Meilleures Ventes (Volume Confirmé)</h3>
                <div className="space-y-3 md:space-y-4">
                   {stats.top10.map((p, i) => (
                     <div key={i} className="flex justify-between items-center p-4 md:p-6 bg-zinc-50 rounded-[25px] md:rounded-[35px] hover:bg-white border border-transparent hover:border-zinc-100 transition-all group shadow-sm">
                        <div className="flex items-center gap-4 md:gap-6">
                           <div className="w-12 h-16 md:w-16 md:h-20 rounded-xl md:rounded-2xl overflow-hidden shadow-sm border border-white bg-zinc-200">
                              <img src={p.img} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                           </div>
                           <div>
                              <p className="font-display font-black uppercase text-xs md:text-sm">{p.name}</p>
                              <p className="text-[7px] md:text-[9px] font-black text-zinc-400 uppercase tracking-widest">{p.count} PIÈCES VENDUES (CONFIRMÉES)</p>
                           </div>
                        </div>
                        <div className="w-10 h-10 rounded-full bg-black text-white flex items-center justify-center font-display font-black italic">#{i+1}</div>
                     </div>
                   ))}
                   {stats.top10.length === 0 && (
                     <p className="text-center text-zinc-300 text-[10px] font-black uppercase tracking-widest py-10">Aucune vente confirmée sur cette période.</p>
                   )}
                </div>
             </div>
           </div>
        )}

        {activeTab === 'leads' && (
           <div className="space-y-6 animate-fade-in-up pb-20">
              <div className="flex flex-col md:flex-row gap-4 justify-between items-center">
                <div className="flex items-center gap-4">
                   <h2 className="text-2xl font-display font-black uppercase tracking-tight">COMMANDES</h2>
                   <select 
                      value={dateFilterDays} 
                      onChange={(e) => setDateFilterDays(Number(e.target.value))}
                      className="bg-white px-4 py-2 rounded-xl border border-zinc-100 text-[8px] font-black uppercase tracking-widest outline-none focus:border-gold"
                    >
                      {DATE_FILTERS.map(f => <option key={f.value} value={f.value}>{f.label}</option>)}
                    </select>
                </div>
                <div className="flex gap-2 overflow-x-auto no-scrollbar w-full md:w-auto pb-2">
                  <button onClick={() => setStatusFilter('All')} className={`px-5 py-3 rounded-full text-[9px] font-black uppercase tracking-widest border whitespace-nowrap flex items-center gap-2 min-h-[44px] ${statusFilter === 'All' ? 'bg-black text-white border-black shadow-lg' : 'bg-white text-zinc-400 border-zinc-100'}`}>
                    TOUT <span className="opacity-30 text-[7px]">{leads.length}</span>
                  </button>
                  {LEAD_STATUSES.map(s => (
                    <button key={s} onClick={() => setStatusFilter(s as any)} className={`px-5 py-3 rounded-full text-[9px] font-black uppercase tracking-widest border whitespace-nowrap flex items-center gap-2 min-h-[44px] ${statusFilter === s ? 'bg-black text-white border-black shadow-lg' : 'bg-white text-zinc-400 border-zinc-100'}`}>
                      {s === 'Pending' ? 'EN ATTENTE' : s === 'Completed' ? 'TERMINÉ' : 'ANNULÉ'}
                      <span className="opacity-30 text-[7px]">{leads.filter(l => l.status === s).length}</span>
