                        <button onClick={() => handleDeleteLead(l.id)} className="w-11 h-11 rounded-full bg-zinc-50 flex items-center justify-center text-zinc-300 hover:bg-red-500 hover:text-white transition-all"><i className="fa-solid fa-trash-can text-xs"></i></button>
                      </div>
                   </div>
                 ))}
              </div>
           </div>
        )}

        {activeTab === 'manage' && (
           <div className="animate-fade-in-up pb-20 space-y-8">
              <div className="flex flex-col items-center text-center space-y-2">
                 <h2 className="text-3xl md:text-5xl font-display font-black uppercase tracking-tighter">STOCK <span className="text-gold italic">LIVE</span></h2>
                 <p className="text-[9px] md:text-[10px] font-black text-zinc-300 uppercase tracking-widest">{products.length} ARTICLES ENREGISTRÉS</p>
              </div>
              <div className="space-y-4">
                 <div className="flex gap-2 overflow-x-auto no-scrollbar pb-2 px-1 justify-center">
                    {['TOUT', ...CATEGORIES].map(cat => (
                       <button 
                          key={cat} 
                          onClick={() => setInventoryCategory(cat)}
                          className={`px-6 py-3 rounded-full text-[9px] font-black uppercase tracking-widest border transition-all whitespace-nowrap min-h-[44px] ${inventoryCategory === cat ? 'bg-black text-white border-black shadow-lg' : 'bg-white text-zinc-400 border-zinc-100 hover:border-zinc-300'}`}
                       >
                          {cat}
                       </button>
                    ))}
                 </div>
                 <div className="relative max-w-md mx-auto">
                    <i className="fa-solid fa-magnifying-glass absolute left-6 top-1/2 -translate-y-1/2 text-zinc-300"></i>
                    <input 
                       type="text" 
                       placeholder="RECHERCHER UN PRODUIT..." 
                       value={inventorySearch}
                       onChange={e => setInventorySearch(e.target.value)}
                       className="w-full bg-white border border-zinc-100 px-12 py-3 rounded-full text-[9px] font-black uppercase tracking-widest focus:border-gold outline-none shadow-sm min-h-[44px]"
                    />
                 </div>
              </div>
              <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4 md:gap-8">
                 {filteredInventory.map(p => (
                   <div key={p.id} onClick={() => setSelectedProduct(p)} className="bg-white p-4 md:p-5 rounded-[30px] md:rounded-[45px] border border-white shadow-sm cursor-pointer group hover:shadow-2xl hover:-translate-y-2 transition-all duration-500">
                      <div className="aspect-[3/4] rounded-[20px] md:rounded-[35px] overflow-hidden mb-4 bg-zinc-50 border border-zinc-100 relative">
                         <img src={Array.isArray(p.image_url) ? p.image_url[0] : p.image_url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-[3s]" />
                         {!p.is_in_stock && (
                            <div className="absolute inset-0 bg-black/70 backdrop-blur-[2px] flex items-center justify-center">
                               <span className="text-[8px] md:text-[10px] font-black text-white uppercase tracking-[0.4em] border border-white/30 px-4 md:px-6 py-2 rounded-full">SOLD OUT</span>
                            </div>
                         )}
                      </div>
                      <h4 className="text-[10px] md:text-[11px] font-black uppercase truncate text-center mb-1 tracking-tight">{p.name}</h4>
                      <p className="text-[9px] md:text-[10px] font-display font-black italic text-gold text-center">{p.price} MAD</p>
                   </div>
                 ))}
              </div>
           </div>
        )}
      </main>

      <AnimatePresence>
        {selectedProduct && (
           <div className="fixed inset-0 z-[5000] flex items-center justify-center p-6">
              <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setSelectedProduct(null)} className="fixed inset-0 bg-black/60 backdrop-blur-md" />
              <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="relative bg-white w-full max-w-sm p-8 md:p-12 rounded-[40px] md:rounded-[60px] shadow-3xl text-center">
                 <button onClick={() => setSelectedProduct(null)} className="absolute top-8 right-8 text-zinc-300 hover:text-black p-2"><i className="fa-solid fa-xmark text-lg"></i></button>
                 <div className="w-32 h-44 md:w-36 md:h-48 mx-auto rounded-[30px] md:rounded-[40px] overflow-hidden mb-8 shadow-2xl border border-zinc-50 bg-zinc-50">
                    <img src={Array.isArray(selectedProduct.image_url) ? selectedProduct.image_url[0] : selectedProduct.image_url} className="w-full h-full object-cover" />
                 </div>
                 <h3 className="text-2xl md:text-3xl font-display font-black uppercase mb-2 tracking-tighter leading-none">{selectedProduct.name}</h3>
                 <p className="text-xs md:text-sm font-display font-black italic text-gold mb-10">{selectedProduct.price} MAD</p>
                 <div className="flex gap-3">
                    <button onClick={() => startEdit(selectedProduct)} className="flex-1 py-5 bg-black text-white rounded-[25px] text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-gold hover:text-black transition-all active:scale-95 min-h-[50px]">MODIFIER</button>
                    <button onClick={() => handleDeleteProduct(selectedProduct)} className="w-16 md:w-20 py-5 bg-red-50 text-red-500 rounded-[25px] hover:bg-red-500 hover:text-white transition-all flex items-center justify-center active:scale-95 min-h-[50px]"><i className="fa-solid fa-trash-can text-base md:text-lg"></i></button>
                 </div>
              </motion.div>
           </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { supabase } from '../lib/supabase';
import { AlertToast } from './ui/AlertToast';
