                    className="w-24 h-32 md:w-32 md:h-44 border-2 border-dashed border-zinc-100 rounded-[25px] md:rounded-[40px] flex flex-col items-center justify-center gap-2 md:gap-4 group hover:bg-zinc-50 transition-all shadow-inner min-h-[44px]"
                  >
                     <i className="fa-solid fa-camera text-zinc-200 text-xl md:text-2xl group-hover:text-gold transition-colors"></i>
                     <span className="text-[7px] md:text-[8px] font-black uppercase text-zinc-300 tracking-[0.2em] text-center px-4 leading-tight">UPLOADER</span>
                     <input type="file" ref={fileInputRef} onChange={handleFileUpload} multiple className="hidden" accept="image/*" />
                  </button>
                  {imageUrls.map((url, i) => (
                    <div key={i} className="relative w-24 h-32 md:w-32 md:h-44 rounded-[25px] md:rounded-[40px] overflow-hidden border border-white shadow-xl group hover:scale-105 transition-transform">
                       <img src={url} className="w-full h-full object-cover" />
                       <button type="button" onClick={() => {
                         triggerConfirm('Supprimer', 'Supprimer définitivement cette image ?', async () => {
                           await deleteFileFromStorage(url);
                           setImageUrls(imageUrls.filter((_, idx) => idx !== i));
                         }, 'Supprimer');
                       }} className="absolute inset-0 bg-black/70 text-white opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center min-h-[44px]"><i className="fa-solid fa-trash-can text-sm md:text-lg"></i></button>
                    </div>
                  ))}
               </div>
            </div>

            <div className="flex flex-col md:flex-row gap-4">
              <button type="submit" className="flex-1 py-8 md:py-10 bg-black text-white rounded-full font-black uppercase tracking-[0.4em] md:tracking-[0.6em] text-[9px] md:text-[11px] shadow-2xl hover:bg-gold hover:text-black transition-all active:scale-95 min-h-[56px]">
                 {editingId ? 'METTRE À JOUR' : 'LANCER LE DROP'}
              </button>
              <button type="button" onClick={resetForm} className="px-10 py-8 md:py-10 bg-white border border-zinc-100 text-[9px] md:text-[11px] font-black uppercase tracking-widest rounded-full hover:bg-zinc-50 transition-all min-h-[56px]">ANNULER</button>
            </div>
          </form>
        )}
      </main>

      <AnimatePresence>
        {selectedProduct && (
           <div className="fixed inset-0 z-[5000] flex items-center justify-center p-6">
              <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setSelectedProduct(null)} className="fixed inset-0 bg-black/60 backdrop-blur-md" />
              <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="relative bg-white w-full max-w-sm p-8 md:p-12 rounded-[40px] md:rounded-[60px] shadow-3xl text-center">
                 <button onClick={() => setSelectedProduct(null)} className="absolute top-8 right-8 text-zinc-300 hover:text-black p-2"><i className="fa-solid fa-xmark text-lg"></i></button>
                 <div className="w-32 h-44 md:w-36 md:h-48 mx-auto rounded-[30px] md:rounded-[40px] overflow-hidden mb-8 shadow-2xl border border-zinc-50 bg-zinc-50">
                    <img src={Array.isArray(selectedProduct.image_url) ? selectedProduct.image_url[0] : selectedProduct.image_url} className="w-full h-full object-cover" />
                 </div>
                 <h3 className="text-2xl md:text-3xl font-display font-black uppercase mb-2 tracking-tighter leading-none">{selectedProduct.name}</h3>
                 <p className="text-xs md:text-sm font-display font-black italic text-gold mb-10">{selectedProduct.price} MAD</p>
                 <div className="flex gap-3">
                    <button onClick={() => startEdit(selectedProduct)} className="flex-1 py-5 bg-black text-white rounded-[25px] text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-gold hover:text-black transition-all active:scale-95 min-h-[50px]">MODIFIER</button>
                    <button onClick={() => handleDeleteProduct(selectedProduct)} className="w-16 md:w-20 py-5 bg-red-50 text-red-500 rounded-[25px] hover:bg-red-500 hover:text-white transition-all flex items-center justify-center active:scale-95 min-h-[50px]"><i className="fa-solid fa-trash-can text-base md:text-lg"></i></button>
                 </div>
              </motion.div>
           </div>
        )}
      </AnimatePresence>
    </div>
  );
};

