  { label: 'Dernières 24 heures', value: 1 },
  { label: '3 derniers jours', value: 3 },
  { label: '7 derniers jours', value: 7 },
  { label: '14 derniers jours', value: 14 },
  { label: '30 derniers jours', value: 30 },
  { label: '3 derniers mois', value: 90 },
  { label: '6 derniers mois', value: 180 },
  { label: 'L\'année dernière', value: 365 }
];

const OFFICIAL_COLORS = [
  { name: 'BLACK', hex: '#000000' },
  { name: 'WHITE', hex: '#FFFFFF' },
  { name: 'RED', hex: '#FF3B30' },
  { name: 'BLUE', hex: '#0038FF' },
  { name: 'GREEN', hex: '#34C759' },
  { name: 'NAVY', hex: '#323264' },
  { name: 'GREY', hex: '#A2A2A2' },
  { name: 'BEIGE', hex: '#F5F5DC' },
  { name: 'GOLD', hex: '#FFD700' },
  { name: 'SILVER', hex: '#C0C0C0' },
  { name: 'PINK', hex: '#FFD1DC' },
  { name: 'ORANGE', hex: '#FF9500' },
  { name: 'YELLOW', hex: '#FFFF00' },
  { name: 'PURPLE', hex: '#AF52DE' },
  { name: 'BROWN', hex: '#A52A2A' }
];

const LEAD_STATUSES = ['Pending', 'Completed', 'Cancelled'];

interface AdminDashboardProps {
  onLogout: () => void;
  triggerConfirm: (title: string, message: string, onConfirm: () => void, confirmLabel?: string) => void;
  setProcessing: (val: boolean) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout, triggerConfirm, setProcessing }) => {
  const [activeTab, setActiveTab] = useState<'nav' | 'add' | 'manage' | 'leads' | 'analytics'>('nav');
  const [products, setProducts] = useState<any[]>([]);
  const [leads, setLeads] = useState<any[]>([]);
  const [allEvents, setAllEvents] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [toasts, setToasts] = useState<any[]>([]);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  const [dateFilterDays, setDateFilterDays] = useState(7);

  const [leadSearch, setLeadSearch] = useState('');
  const [inventorySearch, setInventorySearch] = useState('');
  const [inventoryCategory, setInventoryCategory] = useState('TOUT');
  const [statusFilter, setStatusFilter] = useState<'All' | 'Pending' | 'Completed' | 'Cancelled'>('All');

  const [selectedProduct, setSelectedProduct] = useState<any | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [oldPrice, setOldPrice] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [selectedSizes, setSelectedSizes] = useState<string[]>([]);
  const [selectedColors, setSelectedColors] = useState<string[]>([]);
  const [imageUrls, setImageUrls] = useState<string[]>([]);
  const [isInStock, setIsInStock] = useState(true);

  useEffect(() => {
    fetchGlobalData();
  }, [dateFilterDays]);

  const showToast = (variant: any, title: string, description: string) => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, variant, title, description }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 5000);
  };

  async function fetchGlobalData() {
    setLoading(true);
    const filterDate = new Date();
    filterDate.setDate(filterDate.getDate() - dateFilterDays);
    const dateStr = filterDate.toISOString();

    try {
      const [pRes, lRes, aRes] = await Promise.all([
        supabase.from('products').select('*').order('id', { ascending: false }),
        supabase.from('product_leads').select('*').gte('created_at', dateStr).order('created_at', { ascending: false }),
        supabase.from('site_analytics').select('*').gte('timestamp', dateStr)
      ]);
      if (pRes.data) setProducts(pRes.data);
      if (lRes.data) setLeads(lRes.data);
      if (aRes.data) setAllEvents(aRes.data);
    } catch (e) { showToast('error', 'Erreur', 'Synchronisation impossible.'); } finally { setLoading(false); }
  }

  const stats = useMemo(() => {
    const realRevenue = leads
      .filter(l => l.status === 'Completed')
      .reduce((acc, curr) => acc + (Number(curr.total_price) || 0), 0);

    const potentialRevenue = leads
      .filter(l => l.status !== 'Cancelled')
      .reduce((acc, curr) => acc + (Number(curr.total_price) || 0), 0);

    const views = allEvents.filter(e => e.event_name === 'Page View').length;
    const clicks = allEvents.filter(e => e.event_name === 'WhatsApp Click').length;
    const cartAdds = allEvents.filter(e => e.event_name === 'Add to Cart').length;

    const conversionRate = views > 0 ? ((clicks / views) * 100).toFixed(1) : "0";

    const chartMap: Record<string, { name: string, views: number, clicks: number }> = {};
    const now = new Date();

    for (let i = dateFilterDays - 1; i >= 0; i--) {
      const d = new Date(now.getTime() - (i * 24 * 60 * 60 * 1000));
      const dateKey = d.toISOString().split('T')[0];
      chartMap[dateKey] = { name: dateKey.slice(5), views: 0, clicks: 0 };
    }

    allEvents.forEach(e => {
      const dateKey = e.timestamp?.split('T')[0];
      if (chartMap[dateKey]) {
        if (e.event_name === 'Page View') chartMap[dateKey].views++;
        if (e.event_name === 'WhatsApp Click') chartMap[dateKey].clicks++;
      }
    });

    const productsMap: Record<string, any> = {};
    leads.filter(l => l.status === 'Completed').forEach(l => {
      const itemStrings = l.product_name.split(', ');
      itemStrings.forEach((itemStr: string) => {
        const baseName = itemStr.split(' [')[0].trim();
        if (!productsMap[baseName]) {
          const p = products.find(prod => prod.name === baseName);
          productsMap[baseName] = { 
            name: baseName, 
            count: 0, 
            img: p?.image_url?.[0] || "https://placehold.co/100x150?text=S"
          };
        }
        productsMap[baseName].count++;
      });
    });

    const top10 = Object.values(productsMap).sort((a, b) => b.count - a.count).slice(0, 10);

    return { 
      realRevenue, 
      potentialRevenue, 
      views, 
      conversionRate, 
      clicks, 
      cartAdds, 
      chartData: Object.values(chartMap), 
      top10 
    };
  }, [leads, allEvents, products, dateFilterDays]);

  const resetForm = () => {
    setEditingId(null); setName(''); setPrice(''); setOldPrice(''); setCategory(CATEGORIES[0]);
    setSelectedSizes([]); setSelectedColors([]); setImageUrls([]); setIsInStock(true);
    setActiveTab('manage');
  };

  const startEdit = (p: any) => {
    setEditingId(p.id);
    setName(p.name);
    setPrice(p.price.toString());
    setOldPrice(p.old_price?.toString() || '');
    setCategory(p.category || CATEGORIES[0]);
    setSelectedSizes(p.sizes || []);
    setSelectedColors(p.colors || []);
    setImageUrls(Array.isArray(p.image_url) ? p.image_url : [p.image_url]);
    setIsInStock(p.is_in_stock ?? true);
    setActiveTab('add');
    setSelectedProduct(null);
  };

  const filteredLeads = useMemo(() => {
    let result = [...leads];
    if (statusFilter !== 'All') result = result.filter(l => l.status === statusFilter);
    if (leadSearch) {
      const search = leadSearch.toLowerCase();
      result = result.filter(l => l.order_id.toLowerCase().includes(search) || l.product_name.toLowerCase().includes(search));
    }
    return result;
  }, [leads, leadSearch, statusFilter]);

  const filteredInventory = useMemo(() => {
    let result = [...products];
    if (inventoryCategory !== 'TOUT') {
       result = result.filter(p => p.category?.toUpperCase() === inventoryCategory);
    }
    if (inventorySearch) {
       const search = inventorySearch.toLowerCase();
       result = result.filter(p => p.name?.toLowerCase().includes(search));
    }
    return result;
  }, [products, inventoryCategory, inventorySearch]);

  const NavItems = () => (
    <>
      {[
        { id: 'nav', label: 'BUREAU', icon: 'fa-house' },
        { id: 'leads', label: 'COMMANDES', icon: 'fa-bullseye' },
        { id: 'manage', label: 'INVENTAIRE', icon: 'fa-boxes-stacked' },
        { id: 'add', label: 'AJOUTER DROP', icon: 'fa-plus' }
      ].map((item) => (
        <button 
          key={item.id} 
          onClick={() => { setActiveTab(item.id as any); setMobileMenuOpen(false); }} 
          className={`flex items-center gap-3 text-[10px] font-black uppercase tracking-widest transition-all p-4 rounded-2xl ${activeTab === item.id ? 'bg-black text-white' : 'text-zinc-400 hover:text-black hover:bg-zinc-100'}`}
        >
          <i className={`fa-solid ${item.icon}`}></i>
          {item.label}
        </button>
      ))}
    </>
  );

  const handleDeleteLead = async (id: number) => {
    triggerConfirm('Supprimer', 'Cette action est définitive.', async () => {
      setProcessing(true);
      await supabase.from('product_leads').delete().eq('id', id);
      fetchGlobalData();
      setProcessing(false);
    }, 'Supprimer');
  };

  return (
    <div className="relative min-h-screen bg-[#F7F8FA] text-[#1D1D1F] pb-20 overflow-x-hidden">
      <GlassFilter />
      <div className="fixed top-6 right-6 z-[99999] flex flex-col gap-3 w-full max-w-sm pointer-events-none">
        <AnimatePresence mode="popLayout">
          {toasts.map(toast => <AlertToast key={toast.id} {...toast} onClose={() => {}} />)}
        </AnimatePresence>
      </div>

      <nav className="fixed top-0 w-full z-[100] bg-white/70 backdrop-blur-2xl border-b border-white/40 py-4 px-6 md:px-12 flex justify-between items-center h-20 md:h-24">
        <div className="flex items-center gap-6">
          <button onClick={() => setMobileMenuOpen(true)} className="md:hidden text-xl p-2 min-h-[44px] min-w-[44px] flex items-center justify-center"><i className="fa-solid fa-bars-staggered"></i></button>
          <h1 className="text-xl font-display font-black uppercase tracking-tighter">SWOOP <span className="text-gold italic">HQ</span></h1>
          <div className="hidden md:flex gap-2">
            <NavItems />
          </div>
        </div>
        <button onClick={() => onLogout()} className="text-[10px] font-black uppercase tracking-widest text-red-500 bg-red-50 px-5 py-3 rounded-full hover:bg-red-500 hover:text-white transition-all min-h-[44px]">Quitter</button>
      </nav>

      <AnimatePresence>
        {mobileMenuOpen && (
          <motion.div initial={{ x: '-100%' }} animate={{ x: 0 }} exit={{ x: '-100%' }} className="fixed inset-0 z-[1500] bg-white p-10 flex flex-col gap-4 md:hidden">
            <button onClick={() => setMobileMenuOpen(false)} className="self-end text-xl mb-10 p-2 min-h-[44px]"><i className="fa-solid fa-xmark"></i></button>
            <NavItems />
          </motion.div>
        )}
      </AnimatePresence>

      <main className="pt-24 md:pt-36 container mx-auto px-4 max-w-6xl">
        {/* BUREAU SECTION */}
        {activeTab === 'nav' && (
          <div className="space-y-6 md:space-y-12 animate-fade-in-up pb-20">
            {/* Header with Date Filter */}
            <div className="flex flex-col md:flex-row justify-between items-center gap-4">
               <h2 className="text-3xl font-display font-black uppercase tracking-tight">BUREAU DE CONTRÔLE</h2>
               <select 
                 value={dateFilterDays} 
                 onChange={(e) => setDateFilterDays(Number(e.target.value))}
                 className="bg-white px-5 py-4 md:px-6 md:py-4 rounded-2xl md:rounded-3xl border border-zinc-100 text-[9px] md:text-[10px] font-black uppercase tracking-widest outline-none focus:border-gold shadow-sm appearance-none cursor-pointer min-h-[44px]"
               >
                 {DATE_FILTERS.map(f => <option key={f.value} value={f.value}>{f.label}</option>)}
               </select>
            </div>

            {/* KPI Cards Row */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
               <div className="bg-[#E7F9EE] p-6 rounded-[35px] border border-[#BFF0D4] shadow-sm">
                 <span className="text-[8px] font-black uppercase tracking-[0.4em] text-green-600/50 block mb-2">C.A RÉEL (TERMINÉ)</span>
                 <p className="text-xl md:text-3xl font-display font-black italic text-green-600">{stats.realRevenue.toLocaleString()} <span className="text-[10px]">MAD</span></p>
               </div>
               <div className="bg-black p-6 rounded-[35px] shadow-2xl text-white">
                 <span className="text-[8px] font-black uppercase tracking-[0.4em] text-zinc-500 block mb-2">C.A POTENTIEL</span>
                 <p className="text-xl md:text-3xl font-display font-black italic">{stats.potentialRevenue.toLocaleString()} <span className="text-gold text-[10px]">MAD</span></p>
               </div>
               <div className="bg-white p-6 rounded-[35px] border border-zinc-100 shadow-sm">
                 <span className="text-[8px] font-black uppercase tracking-[0.4em] text-zinc-400 block mb-2">VISITEURS TOTAUX</span>
                 <p className="text-xl md:text-3xl font-display font-black italic">{stats.views}</p>
               </div>
               <div className="bg-white p-6 rounded-[35px] border border-zinc-100 shadow-sm">
                 <span className="text-[8px] font-black uppercase tracking-[0.4em] text-zinc-400 block mb-2">AJOUTS AU PANIER</span>
                 <p className="text-xl md:text-3xl font-display font-black italic">{stats.cartAdds}</p>
               </div>
            </div>

            {/* Dual Graphs Row */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
               <div className="bg-white p-10 rounded-[50px] shadow-sm border border-zinc-100">
                  <div className="flex justify-between items-center mb-10">
                     <h3 className="text-[10px] font-black uppercase tracking-widest text-zinc-400">PAGE VIEWS</h3>
                     <i className="fa-solid fa-users-viewfinder text-zinc-200 text-2xl"></i>
                  </div>
                  <div className="h-[300px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                       <AreaChart data={stats.chartData}>
                          <defs>
                             <linearGradient id="colorViews" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor="#A2A2A2" stopOpacity={0.1}/>
                                <stop offset="95%" stopColor="#A2A2A2" stopOpacity={0}/>
                             </linearGradient>
                          </defs>
                          <XAxis dataKey="name" fontSize={8} axisLine={false} tickLine={false} />
                          <YAxis fontSize={8} axisLine={false} tickLine={false} />
                          <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', fontSize: '10px' }} />
                          <Area type="monotone" dataKey="views" stroke="#A2A2A2" strokeWidth={3} fill="url(#colorViews)" />
                       </AreaChart>
                    </ResponsiveContainer>
                  </div>
               </div>

               <div className="bg-[#0A0A0A] p-10 rounded-[50px] shadow-2xl border border-white/5">
                  <div className="flex justify-between items-center mb-10">
                     <h3 className="text-[10px] font-black uppercase tracking-widest text-gold">WA CLICKS</h3>
                     <i className="fa-brands fa-whatsapp text-gold text-2xl opacity-40"></i>
                  </div>
                  <div className="h-[300px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                       <AreaChart data={stats.chartData}>
                          <defs>
                             <linearGradient id="colorClicks" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor="#D4AF37" stopOpacity={0.3}/>
                                <stop offset="95%" stopColor="#D4AF37" stopOpacity={0}/>
                             </linearGradient>
                          </defs>
                          <XAxis dataKey="name" stroke="#FFFFFF" fontSize={8} axisLine={false} tickLine={false} tick={{ fill: 'white' }} />
                          <YAxis stroke="#FFFFFF" fontSize={8} axisLine={false} tickLine={false} tick={{ fill: 'white' }} />
                          <Tooltip contentStyle={{ backgroundColor: '#111', border: 'none', borderRadius: '12px', color: '#fff', fontSize: '10px' }} />
                          <Area type="monotone" dataKey="clicks" stroke="#D4AF37" strokeWidth={3} fill="url(#colorClicks)" />
                       </AreaChart>
                    </ResponsiveContainer>
                  </div>
               </div>
            </div>

            {/* Top 10 Ranking */}
            <div className="bg-white p-12 rounded-[55px] shadow-sm border border-zinc-100">
               <h3 className="text-xl font-display font-black uppercase mb-10 tracking-widest">Top 10 des Meilleures Ventes (Volume Confirmé)</h3>
               <div className="space-y-4">
                  {stats.top10.map((p, i) => (
                    <div key={i} className="flex justify-between items-center p-8 bg-zinc-50 rounded-[45px] hover:bg-white border border-transparent hover:border-zinc-100 transition-all group">
                       <div className="flex items-center gap-8">
                          <div className="w-20 h-28 rounded-3xl overflow-hidden shadow-sm border border-white bg-zinc-200">
                             <img src={p.img} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
                          </div>
                          <div>
                             <p className="font-display font-black uppercase text-lg">{p.name}</p>
                             <p className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">{p.count} PIÈCES VENDUES (CONFIRMÉES)</p>
                          </div>
                       </div>
                       <div className="w-12 h-12 rounded-full bg-black text-white flex items-center justify-center font-display font-black italic text-lg shadow-xl">#{i+1}</div>
                    </div>
                  ))}
                  {stats.top10.length === 0 && (
                    <p className="text-center text-zinc-300 text-[10px] font-black uppercase tracking-widest py-20">Aucune vente confirmée sur cette période.</p>
                  )}
               </div>
            </div>

            {/* Main Action Grid (Restore the 2 large buttons from image) */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-10">
               <div 
                 onClick={() => setActiveTab('add')}
                 className="bg-white p-16 rounded-[60px] flex flex-col items-center justify-center gap-6 shadow-sm border border-zinc-100 cursor-pointer hover:shadow-2xl hover:-translate-y-2 transition-all duration-500 group"
               >
                 <div className="w-16 h-16 rounded-3xl bg-zinc-50 flex items-center justify-center group-hover:bg-black group-hover:text-white transition-colors">
                   <i className="fa-solid fa-plus text-2xl"></i>
                 </div>
                 <div className="text-center">
                    <h4 className="text-2xl font-display font-black uppercase tracking-tighter">NOUVEAU DROP</h4>
                    <p className="text-[9px] font-black text-zinc-300 uppercase tracking-[0.5em]">PUBLIER UN ARTICLE</p>
                 </div>
               </div>

               <div 
