                 </div>
               </div>
            </div>
          </div>
        )}

        {/* COMMANDES TAB */}
        {activeTab === 'leads' && (
           <div className="space-y-6 animate-fade-in-up pb-20">
              <div className="flex flex-col md:flex-row gap-4 justify-between items-center">
                <div className="flex items-center gap-4">
                   <h2 className="text-2xl font-display font-black uppercase tracking-tight">COMMANDES</h2>
                   <select value={dateFilterDays} onChange={(e) => setDateFilterDays(Number(e.target.value))} className="bg-white px-4 py-2 rounded-xl border border-zinc-100 text-[8px] font-black uppercase tracking-widest outline-none focus:border-gold shadow-sm appearance-none cursor-pointer">
                      {DATE_FILTERS.map(f => <option key={f.value} value={f.value}>{f.label}</option>)}
                   </select>
                </div>
                <div className="flex gap-2 overflow-x-auto no-scrollbar w-full md:w-auto pb-2">
                  <button onClick={() => setStatusFilter('All')} className={`px-5 py-3 rounded-full text-[9px] font-black uppercase tracking-widest border whitespace-nowrap flex items-center gap-2 min-h-[44px] ${statusFilter === 'All' ? 'bg-black text-white border-black shadow-lg' : 'bg-white text-zinc-400 border-zinc-100'}`}>TOUT <span className="opacity-30 text-[7px]">{leads.length}</span></button>
                  {LEAD_STATUSES.map(s => (
                    <button key={s} onClick={() => setStatusFilter(s as any)} className={`px-5 py-3 rounded-full text-[9px] font-black uppercase tracking-widest border whitespace-nowrap flex items-center gap-2 min-h-[44px] ${statusFilter === s ? 'bg-black text-white border-black shadow-lg' : 'bg-white text-zinc-400 border-zinc-100'}`}>{s === 'Pending' ? 'EN ATTENTE' : s === 'Completed' ? 'TERMINÉ' : 'ANNULÉ'} <span className="opacity-30 text-[7px]">{leads.filter(l => l.status === s).length}</span></button>
