                <div className="flex items-center gap-4">
                   <h2 className="text-2xl font-display font-black uppercase tracking-tight">COMMANDES</h2>
                   <select value={dateFilterDays} onChange={(e) => setDateFilterDays(Number(e.target.value))} className="bg-white px-4 py-2 rounded-xl border border-zinc-100 text-[8px] font-black uppercase tracking-widest outline-none focus:border-gold shadow-sm appearance-none cursor-pointer">
                      {DATE_FILTERS.map(f => <option key={f.value} value={f.value}>{f.label}</option>)}
                   </select>
                </div>
                <div className="flex flex-wrap gap-2 w-full md:w-auto pb-2 justify-center md:justify-end">
                  <button onClick={() => setStatusFilter('All')} className={`px-5 py-3 rounded-full text-[9px] font-black uppercase tracking-widest border flex items-center gap-2 min-h-[44px] ${statusFilter === 'All' ? 'bg-black text-white border-black shadow-lg' : 'bg-white text-zinc-400 border-zinc-100'}`}>TOUT <span className="opacity-30 text-[7px]">{leads.length}</span></button>
                  {LEAD_STATUSES.map(s => (
                    <button key={s} onClick={() => setStatusFilter(s as any)} className={`px-5 py-3 rounded-full text-[9px] font-black uppercase tracking-widest border flex items-center gap-2 min-h-[44px] ${statusFilter === s ? 'bg-black text-white border-black shadow-lg' : 'bg-white text-zinc-400 border-zinc-100'}`}>{s === 'Pending' ? 'EN ATTENTE' : s === 'Completed' ? 'TERMINÉ' : 'ANNULÉ'} <span className="opacity-30 text-[7px]">{leads.filter(l => l.status === s).length}</span></button>
                  ))}
                </div>
              </div>
              <div className="relative w-full">
                 <i className="fa-solid fa-magnifying-glass absolute left-6 top-1/2 -translate-y-1/2 text-zinc-300"></i>
                 <input type="text" placeholder="RECHERCHER ID OU ARTICLE..." value={leadSearch} onChange={e => setLeadSearch(e.target.value)} className="bg-white w-full px-12 py-4 rounded-[25px] text-[9px] font-black uppercase tracking-widest outline-none border border-zinc-100 focus:border-gold shadow-sm min-h-[44px]" />
              </div>
              <div className="grid gap-3">
                 {filteredLeads.map(l => (
                   <div key={l.id} className="bg-white p-6 rounded-[25px] border border-zinc-50 shadow-sm flex flex-col md:flex-row justify-between items-center gap-4 group hover:shadow-xl transition-all">
                      <div className="flex items-center gap-4">
                         <div className={`w-2.5 h-2.5 rounded-full animate-pulse`} style={{ backgroundColor: l.status === 'Completed' ? '#34C759' : l.status === 'Cancelled' ? '#FF3B30' : '#D4AF37' }}></div>
                         <div className="flex flex-col items-start">
                            <span className="font-display font-black text-lg text-gold italic">{l.order_id}</span>
                            <h4 className="text-[9px] font-black uppercase tracking-wider text-zinc-400 max-w-xs truncate">{l.product_name}</h4>
                         </div>
                      </div>
                      <div className="text-lg font-display font-black italic">{l.total_price} MAD</div>
                      <div className="flex items-center gap-3 w-full md:w-auto">
                        <select value={l.status} onChange={e => supabase.from('product_leads').update({status: e.target.value}).eq('id', l.id).then(() => fetchGlobalData())} className={`flex-1 md:flex-none px-5 py-2 rounded-full text-[8px] font-black uppercase outline-none border-none cursor-pointer appearance-none text-center min-h-[44px] ${l.status === 'Completed' ? 'bg-green-50 text-green-500' : l.status === 'Cancelled' ? 'bg-red-50 text-red-500' : 'bg-gold/10 text-gold'}`}>
                           {LEAD_STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
                        </select>
                        <button onClick={() => handleDeleteLead(l.id)} className="w-11 h-11 rounded-full bg-zinc-50 flex items-center justify-center text-zinc-300 hover:bg-red-500 hover:text-white transition-all"><i className="fa-solid fa-trash-can text-xs"></i></button>
                      </div>
                   </div>
                 ))}
              </div>
           </div>
        )}

        {/* INVENTAIRE TAB */}
        {activeTab === 'manage' && (
           <div className="animate-fade-in-up pb-20 space-y-8">
              <div className="flex flex-col items-center text-center space-y-2">
                 <h2 className="text-3xl md:text-5xl font-display font-black uppercase tracking-tighter">STOCK <span className="text-gold italic">LIVE</span></h2>
                 <p className="text-[9px] md:text-[10px] font-black text-zinc-300 uppercase tracking-widest">{products.length} ARTICLES ENREGISTRÉS</p>
              </div>
              <div className="space-y-4">
                 <div className="flex flex-wrap gap-2 pb-2 justify-center">
                    {['TOUT', ...CATEGORIES].map(cat => (
                       <button key={cat} onClick={() => setInventoryCategory(cat)} className={`px-6 py-3 rounded-full text-[9px] font-black uppercase tracking-widest border transition-all min-h-[44px] ${inventoryCategory === cat ? 'bg-black text-white border-black shadow-lg' : 'bg-white text-zinc-400 border-zinc-100 hover:border-zinc-300'}`}>{cat}</button>
                    ))}
                 </div>
                 <div className="relative max-w-md mx-auto">
                    <i className="fa-solid fa-magnifying-glass absolute left-6 top-1/2 -translate-y-1/2 text-zinc-300"></i>
                    <input type="text" placeholder="RECHERCHER UN PRODUIT..." value={inventorySearch} onChange={e => setInventorySearch(e.target.value)} className="w-full bg-white border border-zinc-100 px-12 py-3 rounded-full text-[9px] font-black uppercase tracking-widest focus:border-gold outline-none shadow-sm min-h-[44px]" />
                 </div>
              </div>
              <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4 md:gap-8">
                 {filteredInventory.map(p => (
                   <div key={p.id} onClick={() => setSelectedProduct(p)} className="bg-white p-4 md:p-5 rounded-[30px] md:rounded-[45px] border border-zinc-50 shadow-sm cursor-pointer group hover:shadow-2xl hover:-translate-y-2 transition-all duration-500">
                      <div className="aspect-[3/4] rounded-[20px] md:rounded-[35px] overflow-hidden mb-4 bg-zinc-50 border border-zinc-100 relative">
                         <img src={Array.isArray(p.image_url) ? p.image_url[0] : p.image_url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-[3s]" />
                         {!p.is_in_stock && <div className="absolute inset-0 bg-black/70 backdrop-blur-[2px] flex items-center justify-center"><span className="text-[8px] md:text-[10px] font-black text-white uppercase tracking-[0.4em] border border-white/30 px-4 md:px-6 py-2 rounded-full">SOLD OUT</span></div>}
                      </div>
                      <h4 className="text-[10px] md:text-[11px] font-black uppercase truncate text-center mb-1 tracking-tight">{p.name}</h4>
                      <p className="text-[9px] md:text-[10px] font-display font-black italic text-gold text-center">{p.price} MAD</p>
                   </div>
                 ))}
              </div>
           </div>
        )}

        {/* AJOUTER DROP TAB - MATCHING THE IMAGE UI */}
        {activeTab === 'add' && (
          <form onSubmit={async (e) => {
            e.preventDefault();
            setProcessing(true);
            const payload = { name, price: parseFloat(price), old_price: oldPrice ? parseFloat(oldPrice) : null, category, sizes: selectedSizes, colors: selectedColors, image_url: imageUrls, is_in_stock: isInStock };
            if (editingId) await supabase.from('products').update(payload).eq('id', editingId);
            else await supabase.from('products').insert([payload]);
            showToast('success', 'Succès', 'Le drop a été mis à jour.');
            resetForm();
            setProcessing(false);
            fetchGlobalData();
          }} className="space-y-12 pb-32 max-w-4xl mx-auto animate-fade-in-up">

            {/* Section 1: Informations */}
            <div className="bg-white p-8 md:p-14 rounded-[50px] shadow-sm border border-white relative">
               <div className="flex justify-between items-center mb-10">
                  <h3 className="text-2xl font-display font-black uppercase tracking-tight">INFORMATIONS</h3>
                  <div className="flex flex-col items-end gap-2">
                     <span className="text-[8px] font-black text-zinc-300 tracking-widest uppercase">STATUT STOCK</span>
                     <button type="button" onClick={() => setIsInStock(!isInStock)} className={`w-14 h-7 rounded-full p-1 transition-all ${isInStock ? 'bg-[#34C759]' : 'bg-zinc-200'}`}>
                        <div className={`w-5 h-5 bg-white rounded-full shadow-sm transition-transform ${isInStock ? 'translate-x-7' : 'translate-x-0'}`} />
                     </button>
                  </div>
               </div>

               <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="space-y-4">
                     <label className="text-[9px] font-black text-zinc-400 uppercase tracking-widest">NOM DU PRODUIT</label>
                     <input type="text" value={name} onChange={e => setName(e.target.value)} placeholder="Impact Zip Hoodie" className="w-full bg-[#F7F8FA] p-6 rounded-[25px] outline-none text-sm font-black uppercase border border-transparent focus:border-gold/30 transition-all" required />
                  </div>
                  <div className="space-y-4">
                     <label className="text-[9px] font-black text-zinc-400 uppercase tracking-widest">CATÉGORIE</label>
                     <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-[#F7F8FA] p-6 rounded-[25px] outline-none text-sm font-black uppercase border border-transparent appearance-none cursor-pointer">
                        {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                     </select>
                  </div>
                  <div className="space-y-4">
                     <label className="text-[9px] font-black text-zinc-400 uppercase tracking-widest">PRIX (MAD)</label>
                     <input type="number" value={price} onChange={e => setPrice(e.target.value)} placeholder="299" className="w-full bg-[#F7F8FA] p-6 rounded-[25px] outline-none text-sm font-black border border-transparent focus:border-gold/30" required />
                  </div>
                  <div className="space-y-4">
                     <label className="text-[9px] font-black text-zinc-400 uppercase tracking-widest">ANCIEN PRIX (PROMO)</label>
                     <input type="number" value={oldPrice} onChange={e => setOldPrice(e.target.value)} placeholder="Prix d'avant" className="w-full bg-[#F7F8FA] p-6 rounded-[25px] outline-none text-sm font-black border border-transparent focus:border-gold/30 text-red-400" />
                  </div>
               </div>
            </div>

            {/* Section 2: Tailles & Couleurs */}
            <div className="bg-white p-8 md:p-14 rounded-[50px] shadow-sm border border-white">
               <h3 className="text-2xl font-display font-black uppercase tracking-tight mb-12">TAILLES & COULEURS</h3>

               <div className="bg-[#F7F8FA] p-10 rounded-[40px] space-y-12 mb-12">
                  <div className="space-y-6">
                     <span className="text-[9px] font-black text-zinc-400 uppercase tracking-widest">[ VÊTEMENTS ]</span>
                     <div className="flex flex-wrap gap-3">
                        {CLOTHING_SIZES.map(s => (
                           <button key={s} type="button" onClick={() => setSelectedSizes(prev => prev.includes(s) ? prev.filter(x => x !== s) : [...prev, s])} className={`w-16 h-16 flex items-center justify-center rounded-[18px] text-[12px] font-black transition-all ${selectedSizes.includes(s) ? 'bg-black text-white shadow-xl scale-110' : 'bg-white border border-zinc-100 text-zinc-300 hover:border-black'}`}>
                              {s}
                           </button>
                        ))}
                     </div>
                  </div>
                  <div className="space-y-6">
                     <span className="text-[9px] font-black text-zinc-400 uppercase tracking-widest">[ CHAUSSURES ]</span>
                     <div className="flex flex-wrap gap-2">
                        {SHOE_SIZES.map(s => (
                           <button key={s} type="button" onClick={() => setSelectedSizes(prev => prev.includes(s) ? prev.filter(x => x !== s) : [...prev, s])} className={`w-14 h-12 flex items-center justify-center rounded-[14px] text-[10px] font-black transition-all ${selectedSizes.includes(s) ? 'bg-black text-white shadow-lg' : 'bg-white border border-zinc-100 text-zinc-300 hover:border-black'}`}>
                              {s}
                           </button>
                        ))}
                     </div>
                  </div>
               </div>

               <div className="space-y-8">
                  <span className="text-[9px] font-black text-zinc-400 uppercase tracking-widest">PALETTE DE COULEURS OFFICIELLE</span>
                  <div className="bg-[#F7F8FA] p-10 rounded-[40px] grid grid-cols-5 md:grid-cols-10 gap-6">
                     {OFFICIAL_COLORS.map(c => (
                        <div key={c.name} className="flex flex-col items-center gap-3">
                           <button 
                              type="button" 
                              onClick={() => setSelectedColors(prev => prev.includes(c.name) ? prev.filter(x => x !== c.name) : [...prev, c.name])}
                              className={`w-12 h-12 rounded-full flex items-center justify-center transition-all border-2 ${selectedColors.includes(c.name) ? 'ring-2 ring-black ring-offset-4 scale-110' : 'border-white shadow-sm'}`}
                              style={{ backgroundColor: c.hex }}
                           >
                              {selectedColors.includes(c.name) && <i className={`fa-solid fa-check text-[10px] ${c.name === 'WHITE' ? 'text-black' : 'text-white'}`}></i>}
                           </button>
                           <span className="text-[7px] font-black uppercase text-zinc-400 leading-none">{c.name}</span>
                        </div>
                     ))}
                  </div>
               </div>
            </div>

            {/* Section 3: Galerie Photos */}
            <div className="bg-white p-8 md:p-14 rounded-[50px] shadow-sm border border-white">
               <h3 className="text-2xl font-display font-black uppercase tracking-tight mb-12">GALERIE PHOTOS</h3>
               <div className="flex flex-wrap gap-6">
                  <button 
                    type="button" 
                    onClick={() => fileInputRef.current?.click()}
                    className="w-32 h-44 border-2 border-dashed border-zinc-200 rounded-[40px] flex flex-col items-center justify-center gap-4 group hover:bg-zinc-50 transition-all"
                  >
                     <i className="fa-solid fa-camera text-zinc-300 text-2xl group-hover:text-gold transition-colors"></i>
                     <span className="text-[8px] font-black uppercase text-zinc-300 tracking-widest text-center px-4 leading-tight">AJOUTER PHOTO</span>
                     <input type="file" ref={fileInputRef} onChange={handleFileUpload} multiple className="hidden" accept="image/*" />
                  </button>
                  {imageUrls.map((url, i) => (
                    <div key={i} className="relative w-32 h-44 rounded-[40px] overflow-hidden border border-white shadow-xl group">
                       <img src={url} className="w-full h-full object-cover" />
                       <button type="button" onClick={() => {
                         triggerConfirm('Supprimer', 'Supprimer définitivement cette image ?', async () => {
                           await deleteFileFromStorage(url);
                           setImageUrls(imageUrls.filter((_, idx) => idx !== i));
                         }, 'Supprimer');
                       }} className="absolute inset-0 bg-black/70 text-white opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center"><i className="fa-solid fa-trash-can text-lg"></i></button>
                    </div>
                  ))}
               </div>
            </div>

            {/* Final Action Buttons */}
            <div className="flex flex-col md:flex-row gap-4">
              <button type="submit" className="flex-1 py-10 bg-black text-white rounded-full font-black uppercase tracking-[0.6em] text-[11px] shadow-2xl hover:bg-gold hover:text-black transition-all active:scale-95">
                 {editingId ? 'METTRE À JOUR' : 'LANCER LE DROP'}
              </button>
              <button type="button" onClick={resetForm} className="px-10 py-10 bg-white border border-zinc-100 text-[11px] font-black uppercase tracking-widest rounded-full hover:bg-zinc-50 transition-all">ANNULER</button>
            </div>
          </form>
        )}
      </main>

      {/* DETAIL VIEW MODAL */}
      <AnimatePresence>
        {selectedProduct && (
           <div className="fixed inset-0 z-[5000] flex items-center justify-center p-6">
              <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setSelectedProduct(null)} className="fixed inset-0 bg-black/60 backdrop-blur-md" />
              <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="relative bg-white w-full max-w-sm p-12 rounded-[60px] shadow-3xl text-center">
                 <button onClick={() => setSelectedProduct(null)} className="absolute top-8 right-8 text-zinc-300 hover:text-black p-2"><i className="fa-solid fa-xmark text-lg"></i></button>
                 <div className="w-36 h-48 mx-auto rounded-[40px] overflow-hidden mb-8 shadow-2xl bg-zinc-50">
                    <img src={Array.isArray(selectedProduct.image_url) ? selectedProduct.image_url[0] : selectedProduct.image_url} className="w-full h-full object-cover" />
                 </div>
                 <h3 className="text-3xl font-display font-black uppercase mb-2 tracking-tighter leading-none">{selectedProduct.name}</h3>
                 <p className="text-sm font-display font-black italic text-gold mb-10">{selectedProduct.price} MAD</p>
                 <div className="flex gap-3">
                    <button onClick={() => startEdit(selectedProduct)} className="flex-1 py-5 bg-black text-white rounded-[25px] text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-gold hover:text-black transition-all active:scale-95 min-h-[50px]">MODIFIER</button>
                    <button onClick={() => triggerConfirm('Supprimer', 'Supprimer ce produit ?', async () => {
                       await supabase.from('products').delete().eq('id', selectedProduct.id);
                       setSelectedProduct(null);
                       fetchGlobalData();
                    })} className="w-20 py-5 bg-red-50 text-red-500 rounded-[25px] flex items-center justify-center active:scale-95 min-h-[50px]"><i className="fa-solid fa-trash-can text-lg"></i></button>
                 </div>
              </motion.div>
           </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import ProductCard from './components/ProductCard';
import ProductDetail from './components/ProductDetail';
import Boutique from './components/Boutique';
import AboutSection from './components/AboutSection';
import Footer from './components/Footer';
import AdminLogin from './components/AdminLogin';
import AdminDashboard from './components/AdminDashboard';
import Cart from './components/Cart';
import { Product } from './types';
import { supabase } from './lib/supabase';
import { AnimatePresence, motion } from "framer-motion";
import { CustomLoader } from './components/ui/LiquidGlass';

interface ConfirmationState {
  isOpen: boolean;
  title: string;
  message: string;
  onConfirm: () => void;
  confirmLabel?: string;
}

const App: React.FC = () => {
  const [view, setView] = useState<'home' | 'boutique' | 'product' | 'admin'>('home');
  const [selectedProduct, setSelectedProduct] = useState<any | null>(null);
  const [session, setSession] = useState<any>(null);
  const [featuredProducts, setFeaturedProducts] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  const [processing, setProcessing] = useState(false);
  const [confirmModal, setConfirmModal] = useState<ConfirmationState>({
    isOpen: false,
    title: '',
    message: '',
    onConfirm: () => {},
  });

  const triggerConfirm = (title: string, message: string, onConfirm: () => void, confirmLabel = "Confirmer") => {
    setConfirmModal({ isOpen: true, title, message, onConfirm, confirmLabel });
  };

  const closeConfirm = () => setConfirmModal(prev => ({ ...prev, isOpen: false }));

  const logEvent = async (eventName: string, productName: string) => {
    try {
      const { error } = await supabase.from('site_analytics').insert([
        { 
          event_name: eventName, 
          product_name: productName,
          timestamp: new Date().toISOString()
        }
      ]);
      if (error) throw error;
    } catch (err) {
      console.error("[Analytics] Error:", err);
    }
  };

  const logLead = async (orderId: string, productName: string, price: number, details: string) => {
    try {
      const { error } = await supabase.from('product_leads').insert([
        { 
          order_id: orderId, 
          product_name: productName,
          total_price: price,
          details: details,
          status: 'Pending'
        }
      ]);
      if (error) throw error;
    } catch (err) {
      console.error("[Lead] Critical Error:", err);
    }
  };

  const [cart, setCart] = useState<any[]>(() => {
    const saved = localStorage.getItem('swoop_cart');
    return saved ? JSON.parse(saved) : [];
  });
  const [isCartOpen, setIsCartOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem('swoop_cart', JSON.stringify(cart));
  }, [cart]);

  useEffect(() => {
    const hasVisited = sessionStorage.getItem('swoop_visited');
    if (!hasVisited) {
      logEvent('Page View', 'Home');
      sessionStorage.setItem('swoop_visited', 'true');
    }
  }, []);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    const fetchFeatured = async () => {
      setLoading(true);
      const { data, error } = await supabase
        .from('products')
        .select('*')
        .limit(6)
        .order('id', { ascending: false });

      if (!error && data) {
        setFeaturedProducts(data);
      }
      setLoading(false);
    };

    fetchFeatured();

    const handleHashChange = async () => {
      const hash = window.location.hash;
      if (hash === '#admin') {
        setView('admin');
      } else if (hash.startsWith('#product-')) {
        const id = hash.replace('#product-', '');
        const { data } = await supabase.from('products').select('*').eq('id', id).single();
        if (data) {
          setSelectedProduct(data);
          setView('product');
        }
      } else if (hash === '#boutique') {
        setView('boutique');
        setSelectedProduct(null);
      } else {
        setView('home');
        setSelectedProduct(null);
        fetchFeatured(); 
      }
      window.scrollTo(0, 0);
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();
    return () => {
      window.removeEventListener('hashchange', handleHashChange);
      subscription.unsubscribe();
    };
  }, []);

  const handleAddToCart = (item: any) => {
    setCart(prev => {
      const existing = prev.find(i => i.cartId === item.cartId);
      if (existing) {
        return prev.map(i => i.cartId === item.cartId ? { ...i, quantity: i.quantity + item.quantity } : i);
      }
      return [...prev, item];
    });
    setIsCartOpen(true);
  };

  const handleRemoveFromCart = (cartId: string) => {
    setCart(prev => prev.filter(item => item.cartId !== cartId));
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    window.location.hash = '#';
  };

  const renderContent = () => {
    if (view === 'admin') {
      if (!session) return <AdminLogin onLoginSuccess={() => setView('admin')} />;
      return (
        <AdminDashboard 
          onLogout={handleLogout} 
          triggerConfirm={triggerConfirm}
          setProcessing={setProcessing}
        />
      );
    }

    if (view === 'product' && selectedProduct) {
      return (
        <ProductDetail 
          product={selectedProduct} 
          onAddToCart={handleAddToCart} 
          onBack={() => window.location.hash = '#boutique'} 
          logEvent={logEvent}
          logLead={logLead}
        />
      );
    }

    if (view === 'boutique') return <Boutique />;

    return (
      <>
        <Hero />
        <section className="bg-white-luxury py-16 md:py-32 px-6 flex flex-col items-center border-t border-zinc-200">
            <h2 className="text-4xl md:text-8xl font-display font-black text-black-matte uppercase tracking-tighter mb-4 text-center">
              CURATED <span className="text-outline">DROPS</span>
            </h2>
            <div className="w-20 md:w-32 h-[3px] bg-gold mt-4"></div>
        </section>

        <section id="featured" className="relative border-t border-zinc-200 bg-white-luxury">
          <div className="container mx-auto">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 bg-zinc-50 border-x border-zinc-200">
              {loading ? (
                <div className="col-span-full py-20 text-center uppercase tracking-widest text-[10px] text-zinc-400">Chargement...</div>
              ) : (
