                  animate={{ opacity: 1 }} 
                  exit={{ opacity: 0 }} 
                  className="relative flex flex-col items-center gap-10"
                >
                  <CustomLoader />
                  <p className="text-[14px] font-black uppercase tracking-[1em] text-white animate-pulse">
