                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                    className="w-full bg-zinc-50 border border-zinc-100 px-14 py-5 rounded-[25px] text-[11px] font-black uppercase tracking-widest outline-none focus:border-gold transition-all"
                  />
                </div>

                <div className="relative">
                  <Phone className="absolute left-6 top-1/2 -translate-y-1/2 text-zinc-300 w-4 h-4" />
                  <input 
                    type="tel" 
                    placeholder="TÉLÉPHONE (WHATSAPP)" 
                    value={phone}
