import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { WHATSAPP_NUMBER } from '../constants';
import { MapPin, Phone, User, Send } from 'lucide-react';

interface CheckoutModalProps {
  isOpen: boolean;
  onClose: () => void;
  payload: {
    items: any[];
    totalPrice: number;
    productName: string;
    details: string;
  } | null;
  logLead: (orderId: string, productName: string, price: number, details: string, customerData: any) => Promise<void>;
  logEvent: (eventName: string, productName: string) => Promise<void>;
  setCart?: (cart: any[]) => void;
}

const CheckoutModal: React.FC<CheckoutModalProps> = ({ isOpen, onClose, payload, logLead, logEvent, setCart }) => {
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [lat, setLat] = useState<number | null>(null);
  const [lng, setLng] = useState<number | null>(null);
  const [isLocating, setIsLocating] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleGetLocation = () => {
    if (!navigator.geolocation) {
      alert("La géolocalisation n'est pas supportée par votre navigateur.");
      return;
    }

    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      (position) => {
        const { latitude, longitude } = position.coords;
        setLat(latitude);
        setLng(longitude);
        setIsLocating(false);
      },
      (error) => {
        console.error("Error getting location:", error);
        alert("Impossible de récupérer votre position. Veuillez vérifier vos permissions.");
        setIsLocating(false);
      },
      { enableHighAccuracy: true }
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!payload || !name || !phone) return;

    setIsSubmitting(true);
    const orderId = `SWP-${Math.floor(1000 + Math.random() * 9000)}`;

    try {
      // 1. Prepare data mapping according to requirements
      const gpsCoordinates = lat && lng ? `${lat}, ${lng}` : null;

      const customerData = {
        customer_name: name,
        customer_phone: phone,
        latitude: lat,
        longitude: lng,
        gps_coordinates: gpsCoordinates,
        location_captured: !!lat
      };

      // 2. CRITICAL: Insert row into Supabase first
      await Promise.all([
        logLead(orderId, payload.productName, payload.totalPrice, payload.details, customerData),
        logEvent('WhatsApp Click', payload.productName)
      ]);

      // 3. ONLY AFTER success, open WhatsApp
      let message = `Bonjour SWOOP, je suis ${name}. Je souhaite passer commande:\n\n`;
      message += `Order ID: ${orderId}\n`;
      message += `Contact: ${phone}\n`;
      if (gpsCoordinates) message += `Location: https://www.google.com/maps?q=${lat},${lng}\n`;
      message += `\nArticles:\n`;

      payload.items.forEach((item, index) => {
        message += `${index + 1}. ${item.name} [${item.size}/${item.color || 'N/A'}] x${item.quantity}\n`;
      });

      message += `\nTOTAL: ${payload.totalPrice} MAD\n\nMerci de confirmer !`;

      window.open(`https://wa.me/${WHATSAPP_NUMBER.replace('+', '')}?text=${encodeURIComponent(message)}`, '_blank');

      if (setCart) setCart([]);
      onClose();
    } catch (err) {
      console.error("Submission error:", err);
      alert("Une erreur est survenue lors de la validation. Veuillez réessayer.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-[100000] flex items-center justify-center p-6">
        <motion.div 
          initial={{ opacity: 0 }} 
          animate={{ opacity: 1 }} 
          exit={{ opacity: 0 }} 
          onClick={onClose} 
          className="fixed inset-0 bg-black/80 backdrop-blur-2xl" 
        />

        <motion.div 
          initial={{ opacity: 0, scale: 0.9, y: 20 }} 
          animate={{ opacity: 1, scale: 1, y: 0 }} 
          exit={{ opacity: 0, scale: 0.9, y: 20 }} 
          className="relative bg-white w-full max-w-lg p-10 md:p-14 rounded-[50px] shadow-3xl overflow-hidden"
        >
          {/* Decorative Background */}
          <div className="absolute top-0 right-0 w-32 h-32 bg-gold/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl" />

          <div className="relative z-10">
            <div className="text-center mb-12">
              <span className="text-[9px] font-black uppercase tracking-[0.5em] text-gold mb-4 block">Finalisation</span>
              <h2 className="text-4xl font-display font-black uppercase tracking-tighter leading-none mb-2">INFOS LIVRAISON</h2>
              <p className="text-[10px] text-zinc-400 font-bold uppercase tracking-widest">Complétez pour commander via WhatsApp</p>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="space-y-6">
                <div className="relative">
                  <User className="absolute left-6 top-1/2 -translate-y-1/2 text-zinc-300 w-4 h-4" />
                  <input 
                    type="text" 
                    placeholder="NOM COMPLET" 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                    className="w-full bg-zinc-50 border border-zinc-100 px-14 py-5 rounded-[25px] text-[11px] font-black uppercase tracking-widest outline-none focus:border-gold transition-all"
                  />
                </div>

                <div className="relative">
                  <Phone className="absolute left-6 top-1/2 -translate-y-1/2 text-zinc-300 w-4 h-4" />
                  <input 
                    type="tel" 
                    placeholder="TÉLÉPHONE (WHATSAPP)" 
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    required
                    className="w-full bg-zinc-50 border border-zinc-100 px-14 py-5 rounded-[25px] text-[11px] font-black uppercase tracking-widest outline-none focus:border-gold transition-all"
                  />
                </div>

                <button 
                  type="button" 
                  onClick={handleGetLocation}
                  disabled={isLocating}
                  className={`w-full flex items-center justify-between px-8 py-5 rounded-[25px] border-2 transition-all ${lat ? 'bg-green-50 border-green-200 text-green-600' : 'bg-white border-dashed border-zinc-200 text-zinc-400 hover:border-black hover:text-black'}`}
                >
                  <div className="flex items-center gap-4">
                    <MapPin className={`w-4 h-4 ${isLocating ? 'animate-bounce' : ''}`} />
                    <span className="text-[10px] font-black uppercase tracking-widest">
                      {isLocating ? 'Localisation en cours...' : lat ? 'Position Enregistrée' : 'Partager Position GPS'}
                    </span>
                  </div>
                  {lat && <i className="fa-solid fa-check"></i>}
                </button>
              </div>

              <div className="pt-6">
                <button 
                  type="submit" 
                  disabled={isSubmitting || !name || !phone}
                  className="group relative w-full bg-black text-white font-black uppercase tracking-[0.4em] text-[11px] py-8 rounded-[30px] shadow-2xl transition-all hover:bg-gold hover:text-black disabled:opacity-30 disabled:grayscale overflow-hidden"
                >
                  <div className="relative z-10 flex items-center justify-center gap-4">
                    {isSubmitting ? (
                      <span className="animate-pulse">SYNCHRONISATION...</span>
                    ) : (
                      <>
                        <span>Envoyer vers WhatsApp</span>
                        <Send className="w-4 h-4" />
                      </>
                    )}
                  </div>
                </button>
              </div>

              <button 
                type="button" 
                onClick={onClose}
                className="w-full text-[9px] font-black text-zinc-300 uppercase tracking-widest hover:text-black transition-colors"
              >
                Annuler
              </button>
            </form>
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

