import React, { useState, useEffect, useMemo, useRef } from 'react';
import { supabase } from '../lib/supabase';
import { AlertToast } from './ui/AlertToast';
import { AnimatePresence, motion } from "framer-motion";
import { GlassFilter, CustomLoader } from './ui/LiquidGlass';
import { MapPin, ExternalLink, Package, Phone, User, X, CheckCircle2, Clock, XCircle, TrendingUp } from 'lucide-react';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';

const CATEGORIES = ['HOODIES', 'PANTALONS', 'T-SHIRTS', 'SNEAKERS', 'ACCESSOIRES', 'PACKS'];
const DATE_FILTERS = [
  { label: 'Dernières 24 heures', value: 1 },
  { label: '3 derniers jours', value: 3 },
  { label: '7 derniers jours', value: 7 },
  { label: '30 derniers jours', value: 30 },
  { label: 'L\'année dernière', value: 365 }
];

const LEAD_STATUSES = ['Pending', 'Completed', 'Cancelled'];

interface AdminDashboardProps {
  onLogout: () => void;
  triggerConfirm: (title: string, message: string, onConfirm: () => void, confirmLabel?: string) => void;
  setProcessing: (val: boolean) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout, triggerConfirm, setProcessing }) => {
  const [activeTab, setActiveTab] = useState<'nav' | 'leads' | 'manage' | 'add'>('nav');
  const [products, setProducts] = useState<any[]>([]);
  const [leads, setLeads] = useState<any[]>([]);
  const [allEvents, setAllEvents] = useState<any[]>([]);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [toasts, setToasts] = useState<any[]>([]);
  const [dateFilterDays, setDateFilterDays] = useState(7);
  const [selectedLead, setSelectedLead] = useState<any | null>(null);
  const [statusFilter, setStatusFilter] = useState<'All' | 'Pending' | 'Completed' | 'Cancelled'>('All');
  const [leadSearch, setLeadSearch] = useState('');

  // Inventory/Add Drop States (Simplified for restoration focus)
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [imageUrls, setImageUrls] = useState<string[]>([]);

  useEffect(() => {
    fetchGlobalData();
  }, [dateFilterDays]);

  const showToast = (variant: any, title: string, description: string) => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, variant, title, description }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 5000);
  };

  async function fetchGlobalData() {
    setIsRefreshing(true);
    const filterDate = new Date();
    filterDate.setDate(filterDate.getDate() - dateFilterDays);
    const dateStr = filterDate.toISOString();

    try {
      const [pRes, lRes, aRes] = await Promise.all([
        supabase.from('products').select('*').order('id', { ascending: false }),
        supabase.from('product_leads').select('*').gte('created_at', dateStr).order('created_at', { ascending: false }),
        supabase.from('site_analytics').select('*').gte('timestamp', dateStr)
      ]);
      if (pRes.data) setProducts(pRes.data);
      if (lRes.data) setLeads(lRes.data);
      if (aRes.data) setAllEvents(aRes.data);
    } catch (e) { showToast('error', 'Erreur', 'Synchronisation impossible.'); } finally { setIsRefreshing(false); }
  }

  const stats = useMemo(() => {
    const realRevenue = leads.filter(l => l.status === 'Completed').reduce((acc, curr) => acc + (Number(curr.total_price) || 0), 0);
    const potentialRevenue = leads.filter(l => l.status !== 'Cancelled').reduce((acc, curr) => acc + (Number(curr.total_price) || 0), 0);
    const views = allEvents.filter(e => e.event_name === 'Page View').length;
    const clicks = allEvents.filter(e => e.event_name === 'WhatsApp Click').length;

    const chartMap: Record<string, { name: string, views: number, clicks: number }> = {};
    const now = new Date();
    for (let i = dateFilterDays - 1; i >= 0; i--) {
      const d = new Date(now.getTime() - (i * 24 * 60 * 60 * 1000));
      const dateKey = d.toISOString().split('T')[0];
      chartMap[dateKey] = { name: dateKey.split('-')[2] + '/' + dateKey.split('-')[1], views: 0, clicks: 0 };
    }

    allEvents.forEach(e => {
      const dateKey = e.timestamp?.split('T')[0];
      if (chartMap[dateKey]) {
        if (e.event_name === 'Page View') chartMap[dateKey].views++;
        if (e.event_name === 'WhatsApp Click') chartMap[dateKey].clicks++;
      }
    });

    return { realRevenue, potentialRevenue, views, clicks, chartData: Object.values(chartMap) };
  }, [leads, allEvents, dateFilterDays]);

  const filteredLeads = useMemo(() => {
    let result = [...leads];
    if (statusFilter !== 'All') result = result.filter(l => l.status === statusFilter);
    if (leadSearch) {
      const search = leadSearch.toLowerCase();
      result = result.filter(l => l.order_id.toLowerCase().includes(search) || l.customer_name?.toLowerCase().includes(search));
    }
    return result;
  }, [leads, leadSearch, statusFilter]);

  const updateLeadStatus = async (id: number, newStatus: string) => {
    await supabase.from('product_leads').update({ status: newStatus }).eq('id', id);
    fetchGlobalData();
    if (selectedLead?.id === id) setSelectedLead((prev: any) => ({ ...prev, status: newStatus }));
  };

  const parseLeadDetails = (detailsStr: string) => {
    if (!detailsStr) return [];
    return detailsStr.split(' || ').map(itemStr => {
      const parts = itemStr.split(' | ');
      return {
        name: parts[0]?.replace(/^Item \d+: /, '') || 'N/A',
        size: parts[1]?.replace('Size: ', '') || 'N/A',
        color: parts[2]?.replace('Color: ', '') || 'N/A',
        qty: parts[3]?.replace('Qty: ', '') || '1'
      };
    });
  };

  return (
    <div className="relative min-h-screen bg-[#F7F8FA] text-[#1D1D1F] pb-20 overflow-x-hidden">
      <GlassFilter />
      <div className="fixed top-6 right-6 z-[99999] flex flex-col gap-3 w-full max-w-sm pointer-events-none">
        <AnimatePresence mode="popLayout">
          {toasts.map(toast => <AlertToast key={toast.id} {...toast} onClose={() => {}} />)}
        </AnimatePresence>
      </div>

      <nav className="fixed top-0 w-full z-[100] bg-white/70 backdrop-blur-2xl border-b border-zinc-100 py-4 px-12 flex justify-between items-center h-24">
        <h1 className="text-xl font-display font-black uppercase tracking-tighter">SWOOP <span className="text-gold">HQ</span></h1>
        <div className="flex gap-4">
          {['nav', 'leads', 'manage', 'add'].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab as any)} className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-black text-white' : 'text-zinc-400 hover:text-black'}`}>
              {tab === 'nav' ? 'Bureau' : tab === 'leads' ? 'Commandes' : tab === 'manage' ? 'Stocks' : 'Nouveau'}
            </button>
          ))}
          <button onClick={onLogout} className="px-6 py-3 bg-red-50 text-red-500 rounded-2xl text-[10px] font-black uppercase tracking-widest">Quitter</button>
        </div>
      </nav>

      <main className="pt-36 container mx-auto px-4 max-w-6xl">
        {activeTab === 'nav' && (
          <div className="space-y-12 animate-fade-in-up">
            <div className="flex justify-between items-center">
              <h2 className="text-3xl font-display font-black uppercase tracking-tight">ANALYSES GLOBALES</h2>
              <select value={dateFilterDays} onChange={(e) => setDateFilterDays(Number(e.target.value))} className="bg-white px-6 py-4 rounded-3xl border border-zinc-100 text-[10px] font-black uppercase tracking-widest outline-none shadow-sm">
                {DATE_FILTERS.map(f => <option key={f.value} value={f.value}>{f.label}</option>)}
              </select>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
              {[
                { label: 'C.A RÉEL', val: stats.realRevenue, color: 'text-green-600', bg: 'bg-green-50' },
                { label: 'POTENTIEL', val: stats.potentialRevenue, color: 'text-black', bg: 'bg-white' },
                { label: 'VISITES', val: stats.views, color: 'text-black', bg: 'bg-white' },
                { label: 'CLICS WA', val: stats.clicks, color: 'text-gold', bg: 'bg-gold/5' }
              ].map((kpi, i) => (
                <div key={i} className={`${kpi.bg} p-8 rounded-[40px] border border-zinc-50 shadow-sm`}>
                  <span className="text-[8px] font-black uppercase tracking-[0.4em] text-zinc-400 block mb-2">{kpi.label}</span>
                  <p className={`text-3xl font-display font-black italic ${kpi.color}`}>{kpi.val.toLocaleString()} <span className="text-[10px]">{i < 2 ? 'MAD' : ''}</span></p>
                </div>
              ))}
            </div>

            <div className="bg-white p-10 rounded-[50px] shadow-sm border border-zinc-50">
              <div className="flex items-center gap-4 mb-10">
                <TrendingUp className="text-gold" />
                <h3 className="text-xl font-display font-black uppercase tracking-widest">TRAFIC VS CONVERSION</h3>
              </div>
              <div className="h-[400px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={stats.chartData}>
                    <defs>
                      <linearGradient id="colorViews" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#000" stopOpacity={0.1}/>
                        <stop offset="95%" stopColor="#000" stopOpacity={0}/>
                      </linearGradient>
                      <linearGradient id="colorClicks" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#D4AF37" stopOpacity={0.1}/>
                        <stop offset="95%" stopColor="#D4AF37" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900 }} />
                    <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900 }} />
                    <Tooltip contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 20px 50px rgba(0,0,0,0.1)', textTransform: 'uppercase', fontSize: '10px', fontWeight: 900 }} />
                    <Area type="monotone" dataKey="views" name="Visites" stroke="#000" strokeWidth={3} fillOpacity={1} fill="url(#colorViews)" />
                    <Area type="monotone" dataKey="clicks" name="Clics WA" stroke="#D4AF37" strokeWidth={3} fillOpacity={1} fill="url(#colorClicks)" />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'leads' && (
          <div className="space-y-6 animate-fade-in-up">
            <div className="flex justify-between items-center">
              <h2 className="text-2xl font-display font-black uppercase tracking-tight">FLUX COMMANDES</h2>
              <div className="flex gap-2">
                {['All', 'Pending', 'Completed', 'Cancelled'].map(s => (
                  <button key={s} onClick={() => setStatusFilter(s as any)} className={`px-5 py-3 rounded-full text-[9px] font-black uppercase tracking-widest border transition-all ${statusFilter === s ? 'bg-black text-white shadow-xl' : 'bg-white text-zinc-400 border-zinc-100'}`}>
                    {s === 'All' ? 'TOUT' : s === 'Pending' ? 'EN ATTENTE' : s === 'Completed' ? 'PRÊT' : 'ANNULÉ'}
                  </button>
                ))}
              </div>
            </div>
            <div className="grid gap-4">
              {filteredLeads.map(l => (
                <div key={l.id} onClick={() => setSelectedLead(l)} className="bg-white p-8 rounded-[40px] border border-zinc-50 shadow-sm flex justify-between items-center group cursor-pointer hover:shadow-xl transition-all">
                  <div className="flex items-center gap-6">
                    <div className={`w-3 h-3 rounded-full ${l.status === 'Completed' ? 'bg-green-500' : l.status === 'Cancelled' ? 'bg-red-500' : 'bg-gold'}`} />
                    <div>
                      <span className="font-display font-black text-xl tracking-tighter">{l.order_id}</span>
                      <p className="text-[9px] font-black text-zinc-400 uppercase tracking-widest">{l.customer_name || 'Client Inconnu'}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-8">
                    <div className="text-xl font-display font-black italic">{l.total_price} MAD</div>
                    <ExternalLink className="w-5 h-5 text-zinc-200 group-hover:text-gold transition-colors" />
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </main>

      <AnimatePresence>
        {selectedLead && (
          <>
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setSelectedLead(null)} className="fixed inset-0 z-[5000] bg-black/60 backdrop-blur-xl" />
            <motion.div initial={{ x: '100%' }} animate={{ x: 0 }} exit={{ x: '100%' }} className="fixed right-0 top-0 bottom-0 z-[5001] w-full max-w-2xl bg-[#F9F9F9] shadow-2xl overflow-y-auto flex flex-col custom-scrollbar">
              <div className="p-10 border-b bg-white flex justify-between items-center">
                <div>
                  <h3 className="text-3xl font-display font-black uppercase tracking-tighter leading-none">{selectedLead.order_id}</h3>
                  <p className="text-[9px] font-black text-zinc-400 uppercase tracking-widest mt-2">Détails Complets</p>
                </div>
                <button onClick={() => setSelectedLead(null)} className="w-12 h-12 bg-zinc-50 rounded-full flex items-center justify-center hover:bg-zinc-100"><X /></button>
              </div>

              <div className="p-10 space-y-12 pb-32">
                <div className="grid grid-cols-3 gap-3">
                  {LEAD_STATUSES.map(s => (
                    <button key={s} onClick={() => updateLeadStatus(selectedLead.id, s)} className={`py-5 rounded-[25px] text-[10px] font-black uppercase tracking-widest transition-all ${selectedLead.status === s ? 'bg-black text-white shadow-xl' : 'bg-white text-zinc-400 border border-zinc-100'}`}>
                      {s === 'Pending' ? 'ATTENTE' : s === 'Completed' ? 'TERMINÉ' : 'ANNULÉ'}
                    </button>
                  ))}
                </div>

                <div className="space-y-6">
                  <div className="flex items-center gap-4 text-gold"><User className="w-4 h-4" /><h4 className="text-[10px] font-black uppercase tracking-widest">Client</h4></div>
                  <div className="bg-white p-8 rounded-[40px] shadow-sm border border-zinc-50 space-y-4">
                    <div className="flex justify-between items-center border-b border-zinc-50 pb-4"><span className="text-[9px] font-black text-zinc-300">NOM</span><span className="text-sm font-black uppercase">{selectedLead.customer_name}</span></div>
                    <div className="flex justify-between items-center"><span className="text-[9px] font-black text-zinc-300">TÉLÉPHONE</span><a href={`tel:${selectedLead.customer_phone}`} className="text-sm font-black text-gold hover:underline">{selectedLead.customer_phone}</a></div>
                  </div>
                </div>

                {selectedLead.location_captured && (
                  <div className="space-y-6">
                    <div className="flex items-center gap-4 text-gold"><MapPin className="w-4 h-4" /><h4 className="text-[10px] font-black uppercase tracking-widest">Lieu de Livraison</h4></div>
                    <button 
                      onClick={() => window.open(selectedLead.latitude ? `https://www.google.com/maps/search/?api=1&query=${selectedLead.latitude},${selectedLead.longitude}` : `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(selectedLead.gps_coordinates)}`, '_blank')}
                      className="w-full bg-black p-8 text-white rounded-[40px] shadow-xl hover:bg-gold hover:text-black transition-all group flex items-center justify-between"
                    >
                      <div className="flex items-center gap-6 text-left">
                        <MapPin className="w-6 h-6" />
                        <div><span className="block text-[11px] font-black uppercase tracking-widest">Ouvrir dans Google Maps</span><span className="block text-[8px] opacity-40 uppercase tracking-widest mt-1">Localisation Capturée</span></div>
                      </div>
                      <ExternalLink className="w-5 h-5 opacity-40 group-hover:opacity-100" />
                    </button>
                  </div>
                )}

                <div className="space-y-8">
                  <div className="flex items-center gap-4 text-gold"><Package className="w-4 h-4" /><h4 className="text-[10px] font-black uppercase tracking-widest">Panier</h4></div>
                  <div className="space-y-4">
                    {parseLeadDetails(selectedLead.details).map((item, idx) => (
                      <div key={idx} className="bg-white p-8 rounded-[40px] shadow-sm border border-zinc-50 flex justify-between items-center">
                        <div>
                          <h5 className="text-sm font-black uppercase tracking-tight">{item.name}</h5>
                          <div className="flex gap-2 mt-2">
                            <span className="text-[8px] font-black uppercase tracking-widest px-3 py-1 bg-zinc-50 rounded-full text-zinc-400">Taille: {item.size}</span>
                            <span className="text-[8px] font-black uppercase tracking-widest px-3 py-1 bg-zinc-50 rounded-full text-zinc-400">Couleur: {item.color}</span>
                          </div>
                        </div>
                        <span className="text-sm font-black italic text-zinc-300">x{item.qty}</span>
                      </div>
                    ))}
                  </div>
                  <div className="bg-black p-10 rounded-[45px] text-white flex justify-between items-center">
                    <span className="text-[9px] font-black uppercase tracking-widest text-zinc-500">Total Commande</span>
                    <h4 className="text-3xl font-display font-black italic">{selectedLead.total_price} <span className="text-gold">MAD</span></h4>
                  </div>
                </div>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { supabase } from '../lib/supabase';
import { AlertToast } from './ui/AlertToast';
import { AnimatePresence, motion } from "framer-motion";
import { GlassFilter, CustomLoader } from './ui/LiquidGlass';
import { MapPin, ExternalLink, Package, Phone, User, X, CheckCircle2, Clock, XCircle, TrendingUp, Plus, LayoutDashboard, Box, ShoppingCart, Menu, LogOut, Trash2, Edit3, Image as ImageIcon } from 'lucide-react';
import { 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';

const CATEGORIES = ['HOODIES', 'PANTALONS', 'T-SHIRTS', 'SNEAKERS', 'ACCESSOIRES', 'PACKS'];
const CLOTHING_SIZES = ['S', 'M', 'L', 'XL', 'XXL'];
const DATE_FILTERS = [
  { label: '24 Heures', value: 1 },
  { label: '7 Jours', value: 7 },
  { label: '30 Jours', value: 30 },
  { label: '1 An', value: 365 }
];

const LEAD_STATUSES = ['Pending', 'Completed', 'Cancelled'];

const OFFICIAL_COLORS = [
  { name: 'BLACK', hex: '#000000' },
  { name: 'WHITE', hex: '#FFFFFF' },
  { name: 'RED', hex: '#FF3B30' },
  { name: 'GOLD', hex: '#D4AF37' },
  { name: 'NAVY', hex: '#323264' },
  { name: 'GREY', hex: '#A2A2A2' }
];

interface AdminDashboardProps {
  onLogout: () => void;
  triggerConfirm: (title: string, message: string, onConfirm: () => void, confirmLabel?: string) => void;
  setProcessing: (val: boolean) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout, triggerConfirm, setProcessing }) => {
  const [activeTab, setActiveTab] = useState<'nav' | 'leads' | 'manage' | 'add'>('nav');
  const [products, setProducts] = useState<any[]>([]);
  const [leads, setLeads] = useState<any[]>([]);
  const [allEvents, setAllEvents] = useState<any[]>([]);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [toasts, setToasts] = useState<any[]>([]);
  const [dateFilterDays, setDateFilterDays] = useState(7);
  const [selectedLead, setSelectedLead] = useState<any | null>(null);
  const [statusFilter, setStatusFilter] = useState<'All' | 'Pending' | 'Completed' | 'Cancelled'>('All');
  const [leadSearch, setLeadSearch] = useState('');
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Form State for Add/Edit
  const [editingId, setEditingId] = useState<number | null>(null);
  const [formName, setFormName] = useState('');
  const [formPrice, setFormPrice] = useState('');
  const [formOldPrice, setFormOldPrice] = useState('');
  const [formCategory, setFormCategory] = useState(CATEGORIES[0]);
  const [formSizes, setFormSizes] = useState<string[]>([]);
  const [formColors, setFormColors] = useState<string[]>([]);
  const [formImages, setFormImages] = useState<string[]>([]);

  useEffect(() => {
    fetchGlobalData();
  }, [dateFilterDays]);

  const showToast = (variant: any, title: string, description: string) => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, variant, title, description }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 5000);
  };

  async function fetchGlobalData() {
    setIsRefreshing(true);
    const filterDate = new Date();
    filterDate.setDate(filterDate.getDate() - dateFilterDays);
    const dateStr = filterDate.toISOString();

    try {
      const [pRes, lRes, aRes] = await Promise.all([
        supabase.from('products').select('*').order('id', { ascending: false }),
        supabase.from('product_leads').select('*').gte('created_at', dateStr).order('created_at', { ascending: false }),
        supabase.from('site_analytics').select('*').gte('timestamp', dateStr)
      ]);
      if (pRes.data) setProducts(pRes.data);
      if (lRes.data) setLeads(lRes.data);
      if (aRes.data) setAllEvents(aRes.data);
    } catch (e) { 
      showToast('error', 'Erreur', 'Synchronisation impossible.'); 
    } finally { 
      setIsRefreshing(false); 
    }
  }

  const stats = useMemo(() => {
    const realRevenue = leads.filter(l => l.status === 'Completed').reduce((acc, curr) => acc + (Number(curr.total_price) || 0), 0);
    const potentialRevenue = leads.filter(l => l.status !== 'Cancelled').reduce((acc, curr) => acc + (Number(curr.total_price) || 0), 0);
    const views = allEvents.filter(e => e.event_name === 'Page View').length;
    const clicks = allEvents.filter(e => e.event_name === 'WhatsApp Click').length;

    // Graph Data
    const chartMap: Record<string, { name: string, views: number, clicks: number }> = {};
    const now = new Date();
    for (let i = dateFilterDays - 1; i >= 0; i--) {
      const d = new Date(now.getTime() - (i * 24 * 60 * 60 * 1000));
      const dateKey = d.toISOString().split('T')[0];
      chartMap[dateKey] = { name: dateKey.split('-')[2] + '/' + dateKey.split('-')[1], views: 0, clicks: 0 };
    }
    allEvents.forEach(e => {
      const dateKey = e.timestamp?.split('T')[0];
      if (chartMap[dateKey]) {
        if (e.event_name === 'Page View') chartMap[dateKey].views++;
        if (e.event_name === 'WhatsApp Click') chartMap[dateKey].clicks++;
      }
    });

    // Top Selling Products Calculation
    const productRankingMap: Record<string, { name: string, count: number, img: string }> = {};
    leads.filter(l => l.status === 'Completed').forEach(l => {
      const parts = l.product_name.split(', ');
      parts.forEach((pStr: string) => {
        const nameOnly = pStr.split(' [')[0].trim();
        if (!productRankingMap[nameOnly]) {
          const original = products.find(prod => prod.name === nameOnly);
          productRankingMap[nameOnly] = { name: nameOnly, count: 0, img: original?.image_url?.[0] || '' };
        }
        productRankingMap[nameOnly].count++;
      });
    });
    const topProducts = Object.values(productRankingMap).sort((a, b) => b.count - a.count).slice(0, 5);

    return { realRevenue, potentialRevenue, views, clicks, chartData: Object.values(chartMap), topProducts };
  }, [leads, allEvents, products, dateFilterDays]);

  const handleStatusUpdate = async (id: number, status: string) => {
    const { error } = await supabase.from('product_leads').update({ status }).eq('id', id);
    if (!error) {
      fetchGlobalData();
      if (selectedLead?.id === id) setSelectedLead((prev: any) => ({ ...prev, status }));
      showToast('success', 'Statut Mis à Jour', `La commande est maintenant ${status}.`);
    }
  };

  const handleProductDelete = async (id: number) => {
    triggerConfirm('Supprimer', 'Voulez-vous supprimer ce produit ?', async () => {
      setProcessing(true);
      await supabase.from('products').delete().eq('id', id);
      fetchGlobalData();
      setProcessing(false);
      showToast('success', 'Supprimé', 'Produit retiré de l\'inventaire.');
    });
  };

  const resetForm = () => {
    setEditingId(null); setFormName(''); setFormPrice(''); setFormOldPrice('');
    setFormCategory(CATEGORIES[0]); setFormSizes([]); setFormColors([]); setFormImages([]);
  };

  const handleSaveProduct = async () => {
    if (!formName || !formPrice) return;
    setProcessing(true);
    const payload = {
      name: formName,
      price: Number(formPrice),
      old_price: formOldPrice ? Number(formOldPrice) : null,
      category: formCategory,
      sizes: formSizes,
      colors: formColors,
      image_url: formImages,
      is_in_stock: true
    };

    let error;
    if (editingId) {
      const res = await supabase.from('products').update(payload).eq('id', editingId);
      error = res.error;
    } else {
      const res = await supabase.from('products').insert([payload]);
      error = res.error;
    }

    if (!error) {
      fetchGlobalData();
      setActiveTab('manage');
      resetForm();
      showToast('success', 'Succès', editingId ? 'Produit modifié.' : 'Nouveau drop ajouté.');
    }
    setProcessing(false);
  };

  const filteredLeads = useMemo(() => {
    let res = leads;
    if (statusFilter !== 'All') res = res.filter(l => l.status === statusFilter);
    if (leadSearch) res = res.filter(l => l.order_id.toLowerCase().includes(leadSearch.toLowerCase()) || l.customer_name?.toLowerCase().includes(leadSearch.toLowerCase()));
    return res;
  }, [leads, statusFilter, leadSearch]);

  const NavItem = ({ id, icon: Icon, label }: any) => (
    <button 
      onClick={() => { setActiveTab(id); setIsMobileMenuOpen(false); }} 
      className={`flex items-center gap-3 px-6 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === id ? 'bg-black text-white shadow-xl' : 'text-zinc-400 hover:text-black hover:bg-zinc-100'}`}
    >
      <Icon className="w-4 h-4" />
      <span>{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen bg-[#F8F9FA] text-black-matte pb-24">
      <GlassFilter />
      <div className="fixed top-6 right-6 z-[99999] flex flex-col gap-3 w-full max-w-sm pointer-events-none">
        <AnimatePresence mode="popLayout">
          {toasts.map(toast => <AlertToast key={toast.id} {...toast} onClose={() => {}} />)}
        </AnimatePresence>
      </div>

      {/* ADMIN NAVBAR */}
      <nav className="fixed top-0 w-full z-[100] bg-white/80 backdrop-blur-2xl border-b border-zinc-100 h-20 md:h-24 px-6 md:px-12 flex justify-between items-center">
        <div className="flex items-center gap-6">
          <button onClick={() => setIsMobileMenuOpen(true)} className="md:hidden p-3 bg-zinc-50 rounded-xl">
            <Menu className="w-5 h-5" />
          </button>
          <h1 className="text-xl font-display font-black uppercase tracking-tighter">SWOOP <span className="text-gold italic">HQ</span></h1>
        </div>

        {/* DESKTOP NAV */}
        <div className="hidden md:flex gap-2">
          <NavItem id="nav" icon={LayoutDashboard} label="Bureau" />
          <NavItem id="leads" icon={ShoppingCart} label="Commandes" />
          <NavItem id="manage" icon={Box} label="Stocks" />
          <NavItem id="add" icon={Plus} label="Nouveau" />
        </div>

        <div className="flex items-center gap-4">
          <button onClick={fetchGlobalData} className="w-12 h-12 bg-zinc-50 rounded-full flex items-center justify-center hover:bg-zinc-100 transition-colors">
            <TrendingUp className={`w-4 h-4 ${isRefreshing ? 'animate-spin' : ''}`} />
          </button>
          <button onClick={onLogout} className="px-5 py-3 bg-red-50 text-red-500 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-red-500 hover:text-white transition-all">
            <LogOut className="w-4 h-4 md:mr-2 inline" />
            <span className="hidden md:inline">Quitter</span>
          </button>
        </div>
      </nav>

      {/* MOBILE DRAWER */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <>
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setIsMobileMenuOpen(false)} className="fixed inset-0 z-[150] bg-black/60 backdrop-blur-md md:hidden" />
            <motion.div initial={{ x: '-100%' }} animate={{ x: 0 }} exit={{ x: '-100%' }} transition={{ type: 'spring', damping: 25 }} className="fixed top-0 left-0 bottom-0 w-[280px] z-[151] bg-white p-8 flex flex-col gap-4 md:hidden">
              <div className="flex justify-between items-center mb-10">
                <span className="text-sm font-display font-black uppercase tracking-tighter">Navigation</span>
                <button onClick={() => setIsMobileMenuOpen(false)}><X className="w-6 h-6" /></button>
              </div>
              <NavItem id="nav" icon={LayoutDashboard} label="Tableau de Bord" />
              <NavItem id="leads" icon={ShoppingCart} label="Commandes" />
              <NavItem id="manage" icon={Box} label="Inventaire" />
              <NavItem id="add" icon={Plus} label="Ajouter Drop" />
            </motion.div>
          </>
        )}
      </AnimatePresence>

      <main className="pt-32 md:pt-40 container mx-auto px-6 max-w-7xl">
        {/* BUREAU SECTION */}
        {activeTab === 'nav' && (
          <div className="space-y-12 animate-fade-in-up">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
              <h2 className="text-3xl font-display font-black uppercase tracking-tight">ANALYSES DE PERFORMANCE</h2>
              <select value={dateFilterDays} onChange={(e) => setDateFilterDays(Number(e.target.value))} className="bg-white px-6 py-4 rounded-2xl border border-zinc-100 text-[10px] font-black uppercase tracking-widest shadow-sm outline-none">
                {DATE_FILTERS.map(f => <option key={f.value} value={f.value}>{f.label}</option>)}
              </select>
            </div>

            {/* KPI GRID */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
              {[
                { label: 'C.A RÉEL', val: stats.realRevenue, color: 'text-green-600', bg: 'bg-green-50' },
                { label: 'POTENTIEL', val: stats.potentialRevenue, color: 'text-black', bg: 'bg-white' },
                { label: 'VISITES', val: stats.views, color: 'text-black', bg: 'bg-white' },
                { label: 'CLICS WA', val: stats.clicks, color: 'text-gold', bg: 'bg-gold/5' }
              ].map((kpi, i) => (
                <div key={i} className={`${kpi.bg} p-8 rounded-[40px] border border-zinc-50 shadow-sm`}>
                  <span className="text-[8px] font-black uppercase tracking-[0.4em] text-zinc-400 block mb-2">{kpi.label}</span>
                  <p className={`text-2xl md:text-3xl font-display font-black italic ${kpi.color}`}>{kpi.val.toLocaleString()} <span className="text-[10px]">{i < 2 ? 'MAD' : ''}</span></p>
                </div>
              ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              {/* GRAPH */}
              <div className="lg:col-span-2 bg-white p-10 rounded-[50px] shadow-sm border border-zinc-50">
                <div className="flex items-center gap-4 mb-10">
                  <TrendingUp className="text-gold" />
                  <h3 className="text-xl font-display font-black uppercase tracking-widest">TRAFIC VS CONVERSION</h3>
                </div>
                <div className="h-[350px] w-full">
                  <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={stats.chartData}>
                      <defs>
                        <linearGradient id="colorViews" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#000" stopOpacity={0.1}/>
                          <stop offset="95%" stopColor="#000" stopOpacity={0}/>
                        </linearGradient>
                        <linearGradient id="colorClicks" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#D4AF37" stopOpacity={0.1}/>
                          <stop offset="95%" stopColor="#D4AF37" stopOpacity={0}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                      <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900 }} />
                      <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900 }} />
                      <Tooltip contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 20px 50px rgba(0,0,0,0.1)', textTransform: 'uppercase', fontSize: '10px', fontWeight: 900 }} />
                      <Area type="monotone" dataKey="views" name="Visites" stroke="#000" strokeWidth={3} fillOpacity={1} fill="url(#colorViews)" />
                      <Area type="monotone" dataKey="clicks" name="Clics WA" stroke="#D4AF37" strokeWidth={3} fillOpacity={1} fill="url(#colorClicks)" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
              </div>

              {/* TOP PRODUCTS */}
              <div className="bg-black p-10 rounded-[50px] shadow-2xl text-white">
                <h3 className="text-xl font-display font-black uppercase mb-10 tracking-widest">TOP VENTES</h3>
                <div className="space-y-6">
                  {stats.topProducts.map((p, i) => (
                    <div key={i} className="flex items-center justify-between group">
                      <div className="flex items-center gap-4">
                        <div className="w-12 h-12 rounded-xl overflow-hidden bg-zinc-800 flex-shrink-0">
                          <img src={p.img} className="w-full h-full object-cover" />
                        </div>
                        <div>
                          <p className="text-[10px] font-black uppercase tracking-tight truncate w-32">{p.name}</p>
                          <p className="text-[8px] text-gold font-black uppercase tracking-widest">{p.count} PIÈCES</p>
                        </div>
                      </div>
                      <div className="text-xl font-display font-black italic opacity-20">#{i+1}</div>
                    </div>
                  ))}
                  {stats.topProducts.length === 0 && <p className="text-center text-[10px] text-zinc-500 py-20">AUCUNE VENTE ENCORE</p>}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* COMMANDES TAB */}
        {activeTab === 'leads' && (
          <div className="space-y-8 animate-fade-in-up">
            <div className="flex flex-col md:flex-row justify-between items-center gap-6">
              <h2 className="text-2xl font-display font-black uppercase tracking-tight">GESTION DES COMMANDES</h2>
              <div className="flex flex-wrap gap-2">
                {['All', ...LEAD_STATUSES].map(s => (
                  <button 
                    key={s} 
                    onClick={() => setStatusFilter(s as any)} 
                    className={`px-6 py-3 rounded-full text-[9px] font-black uppercase tracking-widest border transition-all ${statusFilter === s ? 'bg-black text-white shadow-xl' : 'bg-white text-zinc-400 border-zinc-100'}`}
                  >
                    {s === 'All' ? 'TOUT' : s === 'Pending' ? 'EN ATTENTE' : s === 'Completed' ? 'TERMINÉ' : 'ANNULÉ'}
                  </button>
                ))}
              </div>
            </div>

            <div className="relative">
              <User className="absolute left-6 top-1/2 -translate-y-1/2 text-zinc-300 w-4 h-4" />
              <input 
                type="text" 
                placeholder="RECHERCHER PAR ID OU NOM CLIENT..." 
                value={leadSearch} 
                onChange={e => setLeadSearch(e.target.value)} 
                className="w-full bg-white px-14 py-5 rounded-[25px] border border-zinc-100 shadow-sm text-[10px] font-black uppercase tracking-widest outline-none focus:border-gold transition-all"
              />
            </div>

            <div className="grid gap-4">
              {filteredLeads.map(l => (
                <div key={l.id} onClick={() => setSelectedLead(l)} className="bg-white p-8 rounded-[40px] border border-zinc-50 shadow-sm flex justify-between items-center group cursor-pointer hover:shadow-xl transition-all">
                  <div className="flex items-center gap-6">
                    <div className={`w-3 h-3 rounded-full ${l.status === 'Completed' ? 'bg-green-500' : l.status === 'Cancelled' ? 'bg-red-500' : 'bg-gold'}`} />
                    <div>
                      <span className="font-display font-black text-xl tracking-tighter">{l.order_id}</span>
                      <p className="text-[9px] font-black text-zinc-400 uppercase tracking-widest">{l.customer_name || 'Inconnu'}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-8">
                    <div className="text-xl font-display font-black italic">{l.total_price} MAD</div>
                    <ExternalLink className="w-5 h-5 text-zinc-200 group-hover:text-gold transition-colors" />
                  </div>
                </div>
              ))}
              {filteredLeads.length === 0 && <div className="text-center py-24 text-zinc-300 text-[10px] font-black uppercase tracking-widest">AUCUNE COMMANDE TROUVÉE</div>}
            </div>
          </div>
        )}

        {/* INVENTAIRE TAB */}
        {activeTab === 'manage' && (
          <div className="space-y-8 animate-fade-in-up">
            <div className="flex justify-between items-center">
              <h2 className="text-2xl font-display font-black uppercase tracking-tight">STOCK & INVENTAIRE</h2>
              <button onClick={() => { resetForm(); setActiveTab('add'); }} className="bg-black text-white px-8 py-4 rounded-full text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-gold hover:text-black transition-all">
                NOUVEAU PRODUIT
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {products.map(p => (
                <div key={p.id} className="bg-white rounded-[40px] overflow-hidden border border-zinc-100 shadow-sm group">
                  <div className="aspect-[4/5] bg-zinc-50 relative">
                    <img src={p.image_url?.[0]} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
                    <div className="absolute top-6 right-6 flex flex-col gap-2">
                      <button onClick={() => { 
                        setEditingId(p.id); 
                        setFormName(p.name); setFormPrice(p.price.toString()); 
                        setFormOldPrice(p.old_price?.toString() || '');
                        setFormCategory(p.category); setFormSizes(p.sizes || []);
                        setFormColors(p.colors || []); setFormImages(p.image_url || []);
                        setActiveTab('add');
                      }} className="w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-lg text-black hover:bg-gold transition-colors"><Edit3 className="w-4 h-4" /></button>
                      <button onClick={() => handleProductDelete(p.id)} className="w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-lg text-red-500 hover:bg-red-500 hover:text-white transition-colors"><Trash2 className="w-4 h-4" /></button>
                    </div>
                  </div>
                  <div className="p-8">
                    <span className="text-[8px] font-black uppercase tracking-widest text-gold mb-2 block">{p.category}</span>
                    <h4 className="text-lg font-display font-black uppercase tracking-tight leading-none mb-4">{p.name}</h4>
                    <div className="flex justify-between items-center">
                      <span className="font-display font-black italic">{p.price} MAD</span>
                      <span className={`text-[8px] font-black uppercase px-3 py-1 rounded-full ${p.is_in_stock ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>
                        {p.is_in_stock ? 'EN STOCK' : 'EPUISÉ'}
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* AJOUTER / MODIFIER TAB */}
        {activeTab === 'add' && (
          <div className="max-w-4xl mx-auto bg-white p-10 md:p-16 rounded-[60px] shadow-sm border border-zinc-50 animate-fade-in-up">
            <div className="flex items-center justify-between mb-16">
              <h2 className="text-4xl font-display font-black uppercase tracking-tighter">{editingId ? 'MODIFIER' : 'AJOUTER'} DROUP</h2>
              <button onClick={() => { resetForm(); setActiveTab('manage'); }} className="text-[9px] font-black uppercase tracking-widest text-zinc-400 hover:text-black transition-colors">ANNULER</button>
            </div>

            <form className="space-y-12" onSubmit={(e) => { e.preventDefault(); handleSaveProduct(); }}>
              {/* Basic Info */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-4">
