                <div className="space-y-8">
                  <div className="flex items-center gap-4 text-gold"><Package className="w-4 h-4" /><h4 className="text-[10px] font-black uppercase tracking-widest">Panier</h4></div>
                  <div className="space-y-4">
                    {selectedLead.details.split(' || ').map((itemStr: string, idx: number) => {
                      const parts = itemStr.split(' | ');
                      return (
                        <div key={idx} className="bg-white p-8 rounded-[40px] shadow-sm border border-zinc-50 flex justify-between items-center">
                          <div>
                            <h5 className="text-sm font-black uppercase tracking-tight">{parts[0]?.replace(/^Item \d+: /, '')}</h5>
                            <div className="flex gap-2 mt-2">
                              <span className="text-[8px] font-black uppercase tracking-widest px-3 py-1 bg-zinc-50 rounded-full text-zinc-400">{parts[1]}</span>
                              <span className="text-[8px] font-black uppercase tracking-widest px-3 py-1 bg-zinc-50 rounded-full text-zinc-400">{parts[2]}</span>
                            </div>
