                    <div className="flex justify-between items-center"><span className="text-[9px] font-black text-zinc-300">TEL</span><a href={`tel:${selectedLead.customer_phone}`} className="text-sm font-black text-gold">{selectedLead.customer_phone}</a></div>
                  </div>
                </div>

                <div className="space-y-6">
                  <div className="flex items-center gap-4 text-gold"><MapPin className="w-4 h-4" /><h4 className="text-[10px] font-black uppercase tracking-widest">LOGISTIQUE</h4></div>
                  <button 
                    onClick={() => window.open(selectedLead.latitude ? `https://www.google.com/maps/search/?api=1&query=${selectedLead.latitude},${selectedLead.longitude}` : `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(selectedLead.gps_coordinates)}`, '_blank')}
                    className="w-full bg-black p-8 text-white rounded-[40px] flex items-center justify-between group"
                  >
                    <div className="flex items-center gap-6">
                      <MapPin className="w-6 h-6 text-gold" />
                      <div className="text-left"><span className="block text-[11px] font-black uppercase">Localiser la livraison</span><span className="block text-[8px] opacity-40 uppercase mt-1">Ouvrir dans Google Maps</span></div>
                    </div>
                    <ArrowUpRight className="opacity-40 group-hover:opacity-100" />
                  </button>
                </div>

                <div className="space-y-8">
                  <div className="flex items-center gap-4 text-gold"><Package className="w-4 h-4" /><h4 className="text-[10px] font-black uppercase tracking-widest">PANIER</h4></div>
                  <div className="space-y-4">
                    {selectedLead.details.split(' || ').map((itemStr: string, idx: number) => {
                      const parts = itemStr.split(' | ');
                      return (
                        <div key={idx} className="bg-white p-8 rounded-[40px] border border-zinc-100 flex justify-between items-center">
                          <div>
                            <h5 className="text-sm font-black uppercase">{parts[0]?.replace(/^Item \d+: /, '')}</h5>
                            <div className="flex gap-2 mt-2">
                              <span className="text-[8px] font-black uppercase px-3 py-1 bg-zinc-50 rounded-full text-zinc-400">{parts[1]}</span>
                              <span className="text-[8px] font-black uppercase px-3 py-1 bg-zinc-50 rounded-full text-zinc-400">{parts[2]}</span>
                            </div>
                          </div>
                          <span className="text-sm font-black italic text-zinc-300">{parts[3]}</span>
                        </div>
                      );
                    })}
                  </div>
                  <div className="bg-black p-10 rounded-[45px] text-white flex justify-between items-center shadow-xl">
                    <span className="text-[9px] font-black uppercase tracking-widest text-zinc-500">Montant Total</span>
                    <h4 className="text-3xl font-display font-black italic">{selectedLead.total_price} <span className="text-gold">MAD</span></h4>
                  </div>
                </div>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
};

