                <div className="space-y-6">
                  <div className="flex items-center gap-4 text-gold"><MapPin className="w-4 h-4" /><h4 className="text-[10px] font-black uppercase tracking-widest">LOGISTIQUE</h4></div>
                  <div className="space-y-4">
                    {/* ADMIN EFFICIENCY: Editable Address */}
                    <textarea 
                      value={editLeadAddress}
                      onChange={(e) => setEditLeadAddress(e.target.value)}
                      placeholder="Coordonnées GPS ou Adresse manuelle..."
                      className="w-full bg-zinc-50 p-8 rounded-[30px] border border-zinc-100 text-[11px] font-black uppercase tracking-widest outline-none focus:border-gold transition-all min-h-[100px] resize-none"
                    />
                    <button 
                      onClick={() => window.open(selectedLead.latitude ? `https://www.google.com/maps/search/?api=1&query=${selectedLead.latitude},${selectedLead.longitude}` : `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(editLeadAddress)}`, '_blank')}
                      className="w-full bg-black p-8 text-white rounded-[40px] flex items-center justify-between group"
                    >
                      <div className="flex items-center gap-6">
                        <MapPin className="w-6 h-6 text-gold" />
                        <div className="text-left"><span className="block text-[11px] font-black uppercase">Localiser la livraison</span><span className="block text-[8px] opacity-40 uppercase mt-1">Ouvrir dans Google Maps</span></div>
