                <div className="space-y-8">
                  <div className="flex items-center gap-4 text-gold"><Package className="w-4 h-4" /><h4 className="text-[10px] font-black uppercase tracking-widest">PANIER (ÉDITABLE)</h4></div>
                  <div className="space-y-4">
                    {/* ADMIN EFFICIENCY: Editable Details */}
                    <textarea 
                      value={editLeadDetails}
                      onChange={(e) => setEditLeadDetails(e.target.value)}
                      placeholder="Format: Item 1: Name | Size: S | Color: BLACK | Qty: 1"
                      className="w-full bg-zinc-50 p-8 rounded-[30px] border border-zinc-100 text-[11px] font-black uppercase tracking-widest outline-none focus:border-gold transition-all min-h-[200px] leading-relaxed"
                    />
